');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('309', 'CREATE OR REPLACE FUNCTION pg_temp.insert_generator(p_schema text, p_table text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_relid oid;
    v_cols text;
    v_vals text;
    v_sql  text;
BEGIN
    SELECT c.oid
      INTO v_relid
      FROM pg_class c
      JOIN pg_namespace n ON n.oid = c.relnamespace
     WHERE n.nspname = p_schema
       AND c.relname = p_table
       AND c.relkind IN (''r'',''p'');

    IF v_relid IS NULL THEN
        RETURN;
    END IF;

    SELECT string_agg(quote_ident(attname), '', '' ORDER BY attnum),
           string_agg(format(''quote_nullable(%I)'', attname), '' || '''', '''' || '' ORDER BY attnum)
      INTO v_cols, v_vals
      FROM pg_attribute
     WHERE attrelid = v_relid
       AND attnum > 0
       AND NOT attisdropped;

    IF v_cols IS NULL THEN
        RETURN;
    END IF;

    INSERT INTO __export_sql(line)
    VALUES (''-- Data for '' || quote_ident(p_schema) || ''.'' || quote_ident(p_table));

    v_sql := format(
        ''INSERT INTO __export_sql(line)
         SELECT ''''INSERT INTO %I.%I (%s) VALUES ('''' || %s || '''');''''
         FROM %I.%I;'',
        p_schema, p_table, v_cols, v_vals, p_schema, p_table
    );

    EXECUTE v_sql;
END;
$function$
');

