INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('317', 'CREATE OR REPLACE FUNCTION public.lumi_activate_faro(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE v_user_id uuid; v_area text; v_key text; v_label text;
BEGIN
  p_params:=public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb));
  v_user_id:=NULLIF(trim(p_params->>''user_id''),'''')::uuid;
  v_area:=NULLIF(trim(COALESCE(p_params->>''area'',p_params->>''checkin_area'')),'''');
  v_key:=NULLIF(trim(COALESCE(NULLIF(p_params->>''value'',''''),p_params->>''faro_key'')),'''');
  IF v_area IS NULL THEN SELECT parent_key INTO v_area FROM public.ui_copy WHERE domain=''faro'' AND lang=''es'' AND key=v_key LIMIT 1; END IF;
  SELECT short_label INTO v_label FROM public.ui_copy WHERE domain=''faro'' AND lang=''es'' AND key=v_key AND parent_key=v_area LIMIT 1;
  IF v_user_id IS NULL OR v_area IS NULL OR v_key IS NULL OR v_label IS NULL THEN RAISE EXCEPTION ''Faro inválido''; END IF;
  INSERT INTO public.user_area_faros(user_id,area,faro_key,faro_text,status,activated_at,updated_at)
  VALUES(v_user_id,v_area::public.life_area,v_key,v_label,''active'',now(),now())
  ON CONFLICT(user_id,area,faro_key) DO UPDATE SET status=''active'',faro_text=excluded.faro_text,activated_at=now(),paused_at=NULL,closed_at=NULL,updated_at=now();
  RETURN public.lumi_open_faros(p_params);
END; $function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('319', 'CREATE OR REPLACE FUNCTION public.lumi_build_share_light_text(p_title text, p_description_short text DEFAULT NULL::text, p_url text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_prefix text;
  v_text text;
BEGIN
  SELECT uc.short_label
  INTO v_prefix
  FROM public.ui_copy uc
  WHERE uc.domain = ''share_light''
    AND uc.key = ''default_prefix''
    AND uc.lang = ''es''
  LIMIT 1;

  v_prefix := COALESCE(
    NULLIF(TRIM(v_prefix), ''''),
    ''Te comparto una pequeña experiencia de LUMEN que podría ayudarte:''
  );

  v_text := v_prefix || '' '' || COALESCE(NULLIF(TRIM(p_title), ''''), ''una experiencia de LUMEN'') || ''.'';

  IF COALESCE(NULLIF(TRIM(p_description_short), ''''), '''') <> '''' THEN
    v_text := v_text || '' '' || TRIM(p_description_short);
  END IF;

  IF COALESCE(NULLIF(TRIM(p_url), ''''), '''') <> '''' THEN
    v_text := v_text || '' '' || TRIM(p_url);
  END IF;

  RETURN v_text;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('325', 'CREATE OR REPLACE FUNCTION public.lumi_close_resource_viewer(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_source       text;
  v_user_id      uuid;
  v_resource_id  uuid;
  v_session_id   uuid;
  v_run_id       uuid;
  v_node_code    text;
  v_node         jsonb;
  v_module_color text;
  v_message      text;
  v_card         jsonb;
  v_after_prompt text;
  v_post_text    text;
BEGIN
  v_source      := coalesce(nullif(trim(p_params->>''source''), ''''), ''lumi'');
  v_user_id     := nullif(trim(p_params->>''user_id''), '''')::uuid;
  v_resource_id := nullif(trim(p_params->>''resource_id''), '''')::uuid;
  v_session_id  := nullif(trim(p_params->>''session_id''), '''')::uuid;
  v_run_id      := nullif(trim(p_params->>''experience_run_id''), '''')::uuid;

  -- FLUJO NUEVO: hay experience_run → EXPERIENCE_POST con post_text real
  IF v_run_id IS NOT NULL THEN
    SELECT e.post_text INTO v_post_text
    FROM public.experience_runs er
    JOIN public.experiences e ON e.id = er.experience_id
    WHERE er.id = v_run_id;

    v_node := public.lumi_get_node(''EXPERIENCE_POST'');

    RETURN jsonb_build_object(
      ''ok'',           true,
      ''code'',         ''EXPERIENCE_POST'',
      ''message'',      coalesce(v_post_text, v_node->>''message'', ''¿Cómo quedaste?''),
      -- FIX 1: lumi_get_node devuelve ''actions'', no ''actions_json''
      ''actions'',      coalesce(v_node->''actions'', ''[]''::jsonb),
      ''content_type'', ''empty_presence'',
      ''content'',      ''{"type": "empty_presence"}''::jsonb,
      ''state'',        ''{}''::jsonb
    );
  END IF;

  -- FLUJO LEGACY: sin experience_run (La Fuente, Santuario)
  v_node_code := CASE v_source
    WHEN ''fuente''    THEN ''POST_VIEWER_FUENTE''
    WHEN ''sanctuary'' THEN ''POST_VIEWER_SANCTUARY''
    ELSE ''POST_VIEWER_LUMI''
  END;

  v_module_color := CASE v_source
    WHEN ''fuente''    THEN ''#2A9068''
    WHEN ''sanctuary'' THEN ''#B88820''
    ELSE ''#7860E0''
  END;

  v_node    := public.lumi_get_node(v_node_code);
  v_message := coalesce(v_node->>''message'', ''Listo.'');

  IF v_source = ''lumi'' AND v_resource_id IS NOT NULL THEN
    BEGIN
      v_card         := public.gaia_get_resource_card(v_user_id, v_resource_id, v_session_id);
      v_after_prompt := nullif(trim(v_card->>''after_prompt''), '''');
      IF v_after_prompt IS NOT NULL THEN
        v_message := v_after_prompt;
      END IF;
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END IF;

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         v_node_code,
    ''message'',      v_message,
    ''actions'',      coalesce(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', ''empty_presence'',
    ''content'',      ''{"type": "empty_presence"}''::jsonb,
    ''state'',        jsonb_build_object(
                      ''contentSource'',     v_source,
                      ''moduleColor'',       v_module_color,
                      ''currentResourceId'', coalesce(v_resource_id::text, ''''),
                      ''currentSessionId'',  coalesce(v_session_id::text, '''')
                    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('324', 'CREATE OR REPLACE FUNCTION public.lumi_close_faro(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE v_user_id uuid; v_id uuid; v_reason text; v_reflection text; v_value text;
BEGIN
 p_params:=public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb)); v_user_id:=NULLIF(trim(p_params->>''user_id''),'''')::uuid;
 v_id:=NULLIF(trim(COALESCE(p_params->>''user_area_faro_id'',p_params->>''resource_id'')),'''')::uuid;
 v_reason:=NULLIF(trim(p_params->>''close_reason''),''''); v_reflection:=NULLIF(trim(p_params->>''close_reflection''),''''); v_value:=NULLIF(trim(p_params->>''close_value_key''),'''');
 IF v_reason IS NULL THEN
   RETURN public.lumi_get_node(''SANCTUARY_FARO_CLOSE'')||jsonb_build_object(''ok'',true,''code'',''SANCTUARY_FARO_CLOSE'',
    ''message'',''Antes de cerrar este tramo, miremos brevemente qué dejó en vos.'',
    ''content_type'',''activity_detail'',''content'',jsonb_build_object(''type'',''activity_detail'',''detail_kind'',''faro_close'',''user_area_faro_id'',v_id::text),
    ''state'',jsonb_build_object(''contentSource'',''sanctuary'',''currentItemId'',v_id::text));
 END IF;
 UPDATE public.user_area_faros SET status=''closed'',closed_at=now(),paused_at=NULL,close_reason=v_reason,close_reflection=v_reflection,close_value_key=v_value,updated_at=now()
 WHERE id=v_id AND user_id=v_user_id;
 RETURN public.lumi_open_faros(p_params);
END; $function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('326', 'CREATE OR REPLACE FUNCTION public.lumi_close_resource_viewer(p_user_id_text text, p_source text DEFAULT ''''::text, p_resource_id_text text DEFAULT ''''::text, p_session_id_text text DEFAULT ''''::text, p_sanctuary_item_id_text text DEFAULT ''''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
begin
  if p_source = ''lumi'' then
    return public.lumi_get_node(''POST_VIEWER_LUMI'');
  end if;

  if p_source = ''fuente'' then
    if coalesce(p_resource_id_text, '''') <> '''' then
      return public.lumi_open_resource(
        p_user_id_text,
        p_resource_id_text,
        ''fuente'',
        coalesce(p_session_id_text, '''')
      );
    end if;

    return public.lumi_get_fuente_items('''', '''', '''');
  end if;

  if p_source = ''sanctuary'' then
    if coalesce(p_sanctuary_item_id_text, '''') <> '''' then
      return public.lumi_open_sanctuary_item(
        p_user_id_text,
        p_sanctuary_item_id_text
      );
    end if;

    if coalesce(p_resource_id_text, '''') <> '''' then
      return public.lumi_open_resource(
        p_user_id_text,
        p_resource_id_text,
        ''sanctuary'',
        coalesce(p_session_id_text, '''')
      );
    end if;

    return public.lumi_get_sanctuary(p_user_id_text);
  end if;

  return public.lumi_get_node(''HOME_DEFAULT'');
end;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('327', 'CREATE OR REPLACE FUNCTION public.lumi_complete_experience_run(p_run_id uuid, p_help_signal text, p_reflection_text text DEFAULT NULL::text, p_perceived_capability_key text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_run            record;
  v_node           jsonb;
  v_effect_options jsonb;
BEGIN
  IF p_help_signal NOT IN (''me_dejo_un_poco_mejor'', ''no_era_para_mi'') THEN
    RAISE EXCEPTION ''help_signal inválido: %. Usar me_dejo_un_poco_mejor o no_era_para_mi'', p_help_signal;
  END IF;

  SELECT er.id, er.user_id, er.session_id, er.experience_id, er.resource_id,
         er.completed_at, er.expected_capability_key, er.perceived_capability_key,
         er.experience_hypothesis_id
  INTO v_run
  FROM public.experience_runs er
  WHERE er.id = p_run_id;

  IF v_run IS NULL THEN
    RAISE EXCEPTION ''experience_run no encontrado: %'', p_run_id;
  END IF;

  IF v_run.completed_at IS NOT NULL THEN
    IF p_help_signal = ''me_dejo_un_poco_mejor'' THEN
      v_node := public.lumi_get_node(''FEEDBACK_EFFECT'');
      SELECT jsonb_agg(jsonb_build_object(''value'', uc.key, ''label'', COALESCE(uc.subtitle, uc.short_label)) ORDER BY uc.sort_order NULLS LAST, uc.key)
      INTO v_effect_options
      FROM public.ui_copy uc
      WHERE uc.domain = ''capability'' AND uc.lang = ''es'' AND COALESCE(uc.subtitle, uc.short_label) IS NOT NULL;
      v_node := jsonb_set(v_node, ''{content,options}'', COALESCE(v_effect_options, ''[]''::jsonb));
      RETURN v_node || jsonb_build_object(
        ''ok'', true,
        ''run_id'', p_run_id,
        ''help_signal'', p_help_signal,
        ''already_completed'', true,
        ''state'', jsonb_build_object(''currentExperienceRunId'', p_run_id)
      );
    END IF;

    v_node := public.lumi_get_node(''POST_FEEDBACK_CLOSED'');
    RETURN v_node || jsonb_build_object(
      ''ok'', true,
      ''code'', ''POST_FEEDBACK_CLOSED'',
      ''content_type'', ''empty_presence'',
      ''content'', jsonb_build_object(''type'', ''empty_presence''),
      ''run_id'', p_run_id,
      ''help_signal'', p_help_signal,
      ''already_completed'', true,
      ''state'', ''{}''::jsonb
    );
  END IF;

  UPDATE public.experience_runs
  SET help_signal = p_help_signal,
      reflection_text = p_reflection_text,
      perceived_capability_key = p_perceived_capability_key,
      saved_to_sanctuary = false,
      completed_at = now()
  WHERE id = p_run_id;

  IF p_help_signal = ''me_dejo_un_poco_mejor'' THEN
    v_node := public.lumi_get_node(''FEEDBACK_EFFECT'');
    SELECT jsonb_agg(jsonb_build_object(''value'', uc.key, ''label'', COALESCE(uc.subtitle, uc.short_label)) ORDER BY uc.sort_order NULLS LAST, uc.key)
    INTO v_effect_options
    FROM public.ui_copy uc
    WHERE uc.domain = ''capability'' AND uc.lang = ''es'' AND COALESCE(uc.subtitle, uc.short_label) IS NOT NULL;
    v_node := jsonb_set(v_node, ''{content,options}'', COALESCE(v_effect_options, ''[]''::jsonb));
    RETURN v_node || jsonb_build_object(
      ''ok'', true,
      ''run_id'', p_run_id,
      ''help_signal'', p_help_signal,
      ''state'', jsonb_build_object(''currentExperienceRunId'', p_run_id)
    );
  END IF;

  v_node := public.lumi_get_node(''POST_FEEDBACK_CLOSED'');
  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''POST_FEEDBACK_CLOSED'',
    ''content_type'', ''empty_presence'',
    ''content'', jsonb_build_object(''type'', ''empty_presence''),
    ''run_id'', p_run_id,
    ''help_signal'', p_help_signal,
    ''state'', ''{}''::jsonb
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('328', 'CREATE OR REPLACE FUNCTION public.lumi_complete_registration(p_params jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_params       jsonb;
  v_user_id      uuid;
  v_name         text;
  v_email_param  text;
  v_auth_email   text;
  v_node         jsonb;
BEGIN
  v_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_user_id := COALESCE(
    NULLIF(v_params->>''user_id'', '''')::uuid,
    auth.uid()
  );

  v_name := NULLIF(BTRIM(COALESCE(
    v_params->>''name'',
    v_params->>''first_name'',
    v_params->>''display_name'',
    ''''
  )), '''');

  v_email_param := NULLIF(LOWER(BTRIM(COALESCE(v_params->>''email'', ''''))), '''');

  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object(
      ''ok'', false,
      ''code'', ''REGISTRATION_PROMPT'',
      ''message'', ''No pudimos terminar de crear tu cuenta ahora. Probá nuevamente.'',
      ''actions'', jsonb_build_array(
        jsonb_build_object(
          ''label'', ''Crear cuenta rápida'',
          ''action'', ''show_register_form'',
          ''variant'', ''solid''
        ),
        jsonb_build_object(
          ''label'', ''Seguir sin cuenta'',
          ''action'', ''dismiss_registration_prompt'',
          ''variant'', ''ghost''
        )
      ),
      ''content_type'', ''empty_presence'',
      ''content'', jsonb_build_object(''type'', ''empty_presence''),
      ''state'', jsonb_build_object(
        ''contentSource'', ''lumi'',
        ''showRegistrationPrompt'', true
      )
    );
  END IF;

  SELECT NULLIF(LOWER(BTRIM(COALESCE(au.email, ''''))), '''')
  INTO v_auth_email
  FROM auth.users au
  WHERE au.id = v_user_id;

  /*
    Criterio canónico MVP:
    REGISTRATION_SUCCESS sólo puede devolverse si Auth ya tiene email real.
    Si Supabase Auth queda pendiente de confirmación y au.email sigue null,
    no consolidamos éxito falso.
  */
  IF v_auth_email IS NULL THEN
    RETURN jsonb_build_object(
      ''ok'', false,
      ''code'', ''REGISTRATION_PROMPT'',
      ''message'', ''No pudimos confirmar la cuenta todavía. Revisá el email e intentá nuevamente.'',
      ''actions'', jsonb_build_array(
        jsonb_build_object(
          ''label'', ''Crear cuenta rápida'',
          ''action'', ''show_register_form'',
          ''variant'', ''solid''
        ),
        jsonb_build_object(
          ''label'', ''Seguir sin cuenta'',
          ''action'', ''dismiss_registration_prompt'',
          ''variant'', ''ghost''
        )
      ),
      ''content_type'', ''empty_presence'',
      ''content'', jsonb_build_object(''type'', ''empty_presence''),
      ''state'', jsonb_build_object(
        ''contentSource'', ''lumi'',
        ''showRegistrationPrompt'', true,
        ''registrationPending'', true
      )
    );
  END IF;

  /*
    Consolidación mínima en public.users.
    No asumimos columnas salvo id.
    Luego actualizamos sólo columnas existentes.
  */
  INSERT INTO public.users (id)
  VALUES (v_user_id)
  ON CONFLICT (id) DO NOTHING;

  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = ''public''
      AND table_name = ''users''
      AND column_name = ''email''
  ) THEN
    UPDATE public.users
    SET email = v_auth_email
    WHERE id = v_user_id;
  END IF;

  IF v_name IS NOT NULL AND EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = ''public''
      AND table_name = ''users''
      AND column_name = ''name''
  ) THEN
    UPDATE public.users
    SET name = v_name
    WHERE id = v_user_id;
  END IF;

  IF v_name IS NOT NULL AND EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = ''public''
      AND table_name = ''users''
      AND column_name = ''display_name''
  ) THEN
    UPDATE public.users
    SET display_name = v_name
    WHERE id = v_user_id;
  END IF;

  IF v_name IS NOT NULL AND EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = ''public''
      AND table_name = ''users''
      AND column_name = ''first_name''
  ) THEN
    UPDATE public.users
    SET first_name = v_name
    WHERE id = v_user_id;
  END IF;

  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = ''public''
      AND table_name = ''users''
      AND column_name = ''has_visited''
  ) THEN
    UPDATE public.users
    SET has_visited = true
    WHERE id = v_user_id;
  END IF;

  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = ''public''
      AND table_name = ''users''
      AND column_name = ''registration_prompt_dismissed''
  ) THEN
    UPDATE public.users
    SET registration_prompt_dismissed = true
    WHERE id = v_user_id;
  END IF;

  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = ''public''
      AND table_name = ''users''
      AND column_name = ''updated_at''
  ) THEN
    UPDATE public.users
    SET updated_at = now()
    WHERE id = v_user_id;
  END IF;

  v_node := public.lumi_get_node(''REGISTRATION_SUCCESS'');

  RETURN jsonb_build_object(
    ''ok'', true,
    ''code'', ''REGISTRATION_SUCCESS'',
    ''message'', COALESCE(
      v_node->>''message'',
      v_node->>''message_text'',
      ''Listo. Todo lo que construiste hasta ahora queda guardado con vos.''
    ),
    ''actions'', COALESCE(
      v_node->''actions'',
      v_node->''actions_json'',
      jsonb_build_array(
        jsonb_build_object(
          ''label'', ''Seguimos'',
          ''action'', ''go_home'',
          ''variant'', ''ghost''
        )
      )
    ),
    ''content_type'', COALESCE(
      v_node->>''content_type'',
      ''empty_presence''
    ),
    ''content'', COALESCE(
      v_node->''content'',
      v_node->''content_json'',
      jsonb_build_object(''type'', ''empty_presence'')
    ),
    ''state'', jsonb_build_object(
      ''contentSource'', ''lumi'',
      ''showRegistrationPrompt'', false,
      ''is_anonymous'', false,
      ''userId'', v_user_id,
      ''name'', v_name,
      ''email'', v_auth_email
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('329', 'CREATE OR REPLACE FUNCTION public.lumi_complete_scan(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_node jsonb;
  v_options jsonb;
  v_resource_id uuid;
  v_session_id uuid;
  v_experience_run_id uuid;
  v_user_id uuid;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb));
  v_resource_id := NULLIF(trim(COALESCE(p_params->>''resource_id'',p_params->>''currentResourceId'','''')),'''')::uuid;
  v_session_id := NULLIF(trim(COALESCE(p_params->>''session_id'',p_params->>''currentSessionId'','''')),'''')::uuid;
  v_experience_run_id := NULLIF(trim(COALESCE(p_params->>''experience_run_id'',p_params->>''currentExperienceRunId'','''')),'''')::uuid;
  v_user_id := NULLIF(trim(COALESCE(p_params->>''user_id'','''')),'''')::uuid;

  IF v_resource_id IS NOT NULL THEN
    v_node := public.lumi_get_node(''EXPERIENCE_PRE'');
    RETURN v_node || jsonb_build_object(
      ''ok'',true,
      ''state'',jsonb_build_object(
        ''currentResourceId'',v_resource_id::text,
        ''currentSessionId'',COALESCE(v_session_id::text,''''),
        ''currentExperienceRunId'',COALESCE(v_experience_run_id::text,''''),
        ''contentSource'',''lumi''));
  END IF;

  v_options := public.lumi_checkin_options(''state'',v_user_id,''H1'');
  IF jsonb_array_length(v_options)=0 THEN
    RETURN public.lumi_checkin_no_match(''state'',''H1'',jsonb_build_object(
      ''currentSessionId'',COALESCE(v_session_id::text,''''),
      ''checkinHemisphere'',''H1'',''contentSource'',''lumi''));
  END IF;

  v_node := public.lumi_get_node(''CHECKIN_STATE'');
  RETURN v_node || jsonb_build_object(
    ''ok'',true,
    ''code'',''CHECKIN_STATE'',
    ''content_type'',''checkin_options'',
    ''content'',jsonb_build_object(''type'',''checkin_options'',''step'',''state'',''options'',v_options),
    ''state'',jsonb_build_object(
      ''currentSessionId'',COALESCE(v_session_id::text,''''),
      ''checkinHemisphere'',''H1'',''checkinArea'','''',''checkinState'','''',
      ''checkinFaro'','''',''checkinCapability'','''',''checkinTime'','''',''contentSource'',''lumi''));
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('330', 'CREATE OR REPLACE FUNCTION public.lumi_complete_share_light(p_params jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_user_id uuid;
  v_share_light_id uuid;
  v_channel_text text;
  v_channel public.share_light_channel;
  v_result text;
  v_success boolean;
  v_final_text text;
  v_event_type public.share_light_event_type;
  v_status public.share_light_status;
  v_share record;
  v_node jsonb;
  v_code text;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_user_id := NULLIF(TRIM(COALESCE(
    p_params->>''user_id'',
    p_params->>''currentUserId'',
    ''''
  )), '''')::uuid;

  v_share_light_id := NULLIF(TRIM(COALESCE(
    p_params->>''share_light_id'',
    p_params->>''currentShareLightId'',
    ''''
  )), '''')::uuid;

  v_channel_text := COALESCE(NULLIF(TRIM(p_params->>''channel''), ''''), ''unknown'');

  v_channel := CASE
    WHEN v_channel_text IN (''clipboard'', ''native_share'', ''manual'', ''link'', ''whatsapp'', ''email'')
      THEN v_channel_text::public.share_light_channel
    ELSE ''unknown''::public.share_light_channel
  END;

  v_result := COALESCE(NULLIF(TRIM(p_params->>''result''), ''''), ''copied'');
  v_success := COALESCE((p_params->>''success'')::boolean, true);

  v_final_text := NULLIF(TRIM(COALESCE(
    p_params->>''final_text'',
    p_params->>''share_text'',
    ''''
  )), '''');

  IF v_share_light_id IS NULL THEN
    v_node := public.lumi_get_node(''SHARE_LIGHT_COMPLETE_INVALID'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARE_LIGHT_COMPLETE_INVALID'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  SELECT *
  INTO v_share
  FROM public.share_light_circulations
  WHERE id = v_share_light_id
    AND (v_user_id IS NULL OR created_by_user_id = v_user_id)
  LIMIT 1;

  IF NOT FOUND THEN
    v_node := public.lumi_get_node(''SHARE_LIGHT_NOT_FOUND'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARE_LIGHT_NOT_FOUND'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  IF v_success = false OR v_result = ''failed'' THEN
    v_event_type := ''failed'';
    v_status := ''failed'';
  ELSIF v_channel = ''native_share'' THEN
    v_event_type := ''shared'';
    v_status := ''shared'';
  ELSE
    v_event_type := ''copied'';
    v_status := ''copied'';
  END IF;

  UPDATE public.share_light_circulations
  SET
    status = v_status,
    final_text = COALESCE(v_final_text, editable_text),
    copied_at = CASE WHEN v_status = ''copied'' THEN now() ELSE copied_at END,
    shared_at = CASE WHEN v_status = ''shared'' THEN now() ELSE shared_at END,
    updated_at = now()
  WHERE id = v_share_light_id
    AND (v_user_id IS NULL OR created_by_user_id = v_user_id)
  RETURNING *
  INTO v_share;

  INSERT INTO public.share_light_events (
    share_light_id, user_id, session_id, event_type, channel, surface, success, error_message, metadata
  )
  VALUES (
    v_share.id,
    COALESCE(v_user_id, v_share.created_by_user_id),
    v_share.session_id,
    v_event_type,
    v_channel,
    v_share.source_surface,
    v_success,
    NULLIF(TRIM(COALESCE(p_params->>''error_message'', '''')), ''''),
    jsonb_build_object(
      ''result'', v_result,
      ''text_length'', length(COALESCE(v_share.final_text, v_share.editable_text))
    )
  );

  v_code := CASE WHEN v_status = ''failed'' THEN ''SHARE_LIGHT_FAILED'' ELSE ''SHARE_LIGHT_DONE'' END;
  v_node := public.lumi_get_node(v_code);

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', v_code,
    ''content_type'', ''share_light_editor'',
    ''content'', jsonb_build_object(
      ''type'', ''share_light_editor'',
      ''share_light_id'', v_share.id,
      ''status'', v_share.status,
      ''share_text'', COALESCE(v_share.final_text, v_share.editable_text)
    ),
    ''state'', jsonb_build_object(
      ''currentShareLightId'', v_share.id
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('348', 'CREATE OR REPLACE FUNCTION public.lumi_get_scan()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_node record;
  v_content jsonb;
BEGIN
  SELECT code, message_text, actions_json, content_json
  INTO v_node
  FROM public.lumen_nodes
  WHERE moment_type = ''landing_scan''
    AND active = true
  ORDER BY random()
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      ''ok'', false,
      ''error'', ''no_scan_available''
    );
  END IF;

  v_content :=
    COALESCE(v_node.content_json, ''{}''::jsonb)
    || jsonb_build_object(
      ''type'', ''activity_detail'',
      ''detail_kind'', ''landing_scan'',
      ''source'', ''home''
    );

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         v_node.code,
    ''message'',      COALESCE(v_node.message_text, ''''),
    ''actions'',      COALESCE(v_node.actions_json, ''[]''::jsonb),
    ''content_type'', ''activity_detail'',
    ''content'',      v_content,
    ''state'',        jsonb_build_object(
      ''contentSource'', ''lumi''
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('331', 'CREATE OR REPLACE FUNCTION public.lumi_complete_shared_light(p_params jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_token text;
  v_share record;
  v_node jsonb;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_token := NULLIF(TRIM(COALESCE(
    p_params->>''share_token'',
    p_params->>''currentShareToken'',
    p_params->>''value'',
    ''''
  )), '''');

  SELECT *
  INTO v_share
  FROM public.share_light_circulations
  WHERE share_token = v_token
    AND status NOT IN (''revoked'', ''expired'')
    AND (expires_at IS NULL OR expires_at > now())
  LIMIT 1;

  IF NOT FOUND THEN
    v_node := public.lumi_get_node(''SHARED_LIGHT_NOT_FOUND'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARED_LIGHT_NOT_FOUND'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  INSERT INTO public.share_light_events (
    share_light_id, user_id, session_id, event_type, channel, surface, success, metadata
  )
  VALUES (
    v_share.id, NULL, NULL, ''opened'', ''link'', ''unknown'', true,
    jsonb_build_object(''anonymous'', true, ''step'', ''resource_completed'')
  );

  v_node := public.lumi_get_node(''SHARED_LIGHT_FEEDBACK'');

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''SHARED_LIGHT_FEEDBACK'',
    ''content_type'', ''empty_presence'',
    ''content'', jsonb_build_object(
      ''type'', ''empty_presence'',
      ''source'', ''shared_light'',
      ''share_light_id'', v_share.id,
      ''share_token'', v_share.share_token
    ),
    ''state'', jsonb_build_object(
      ''contentSource'', ''shared_light'',
      ''currentShareLightId'', v_share.id,
      ''currentShareToken'', v_share.share_token
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('332', 'CREATE OR REPLACE FUNCTION public.lumi_confirm_remove_from_sanctuary(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  RETURN public.lumi_confirm_remove_from_sanctuary(
    p_params->>''user_id'',
    p_params->>''sanctuary_item_id''
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('333', 'CREATE OR REPLACE FUNCTION public.lumi_confirm_remove_from_sanctuary(p_user_id_text text, p_sanctuary_item_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id           uuid;
  v_sanctuary_item_id uuid;
  v_detail            jsonb;
  v_node              jsonb;
  v_content           jsonb;
BEGIN
  v_user_id := NULLIF(TRIM(p_user_id_text), '''')::uuid;

  v_sanctuary_item_id := NULLIF(
    TRIM(BOTH '''''''' FROM TRIM(COALESCE(p_sanctuary_item_id_text, ''''))),
    ''''
  )::uuid;

  v_detail := public.lumi_open_sanctuary_item(
    p_user_id_text,
    p_sanctuary_item_id_text
  );

  v_node := public.lumi_get_node(''SANCTUARY_REMOVE_CONFIRM'');

  v_content :=
    (COALESCE(v_detail->''content'', ''{}''::jsonb) - ''type'')
    || jsonb_build_object(
      ''type'', ''activity_detail'',
      ''detail_kind'', ''sanctuary'',
      ''source'', ''sanctuary''
    );

  RETURN jsonb_build_object(
    ''ok'', true,
    ''code'', ''SANCTUARY_REMOVE_CONFIRM'',
    ''message'', COALESCE(v_node->>''message'', ''¿Querés quitar esto de tu Santuario?''),
    ''actions'', jsonb_build_array(
      jsonb_build_object(
        ''label'',  ''Sí, quitar'',
        ''action'', ''remove_from_sanctuary'',
        ''value'',  COALESCE(v_sanctuary_item_id::text, '''')
      ),
      jsonb_build_object(
        ''label'',  ''No, volver'',
        ''action'', ''open_sanctuary'',
        ''value'',  ''''
      )
    ),
    ''content_type'', ''activity_detail'',
    ''content'',      v_content,
    ''state'',        COALESCE(v_detail->''state'', ''{}''::jsonb)
                    || jsonb_build_object(
                         ''contentSource'',   ''sanctuary'',
                         ''moduleColor'',     ''#B88820'',
                         ''spacesMenuOpen'',  false,
                         ''filterPanelOpen'', false
                       )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('334', 'CREATE OR REPLACE FUNCTION public.lumi_dismiss_registration_prompt(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id uuid;
  v_node    jsonb;
BEGIN
  v_user_id := nullif(trim(p_params->>''user_id''), '''')::uuid;

  IF v_user_id IS NULL THEN
    RETURN public.lumi_get_node(''HOME_DEFAULT'')
      || jsonb_build_object(''ok'', false, ''error'', ''user_id requerido'', ''state'', ''{}''::jsonb);
  END IF;

  UPDATE public.users
  SET registration_prompt_dismissed = true
  WHERE id = v_user_id;

  v_node := public.lumi_get_node(''REGISTRATION_DISMISSED'');

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         ''REGISTRATION_DISMISSED'',
    ''message'',      coalesce(v_node->>''message'', ''Perfecto, sin apuro.''),
    ''actions'',      coalesce(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', ''empty_presence'',
    ''content'',      ''{"type":"empty_presence"}''::jsonb,
    ''state'',        jsonb_build_object(
                      ''show_register_prompt'', false
                    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('335', 'CREATE OR REPLACE FUNCTION public.lumi_dispatch(p_action text, p_params jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_fn     text;
  v_result jsonb;
BEGIN
  -- Sanitizar y construir el nombre de función
  -- ''go_home''     → ''lumi_go_home''
  -- ''open_faros''  → ''lumi_open_faros''
  v_fn := ''lumi_'' || regexp_replace(
    lower(trim(p_action)),
    ''[^a-z0-9_]'', ''_'', ''g''
  );

  -- Ejecutar dinámicamente — cero knowledge del dispatcher
  BEGIN
    EXECUTE format(''SELECT public.%I($1)'', v_fn)
    INTO   v_result
    USING  p_params;

  EXCEPTION
    -- Función no existe: mensaje claro
    WHEN undefined_function THEN
      RETURN public.lumi_get_node(''HOME_DEFAULT'')
        || jsonb_build_object(
             ''ok'',    false,
             ''error'', ''action_not_found: '' || v_fn,
             ''state'', ''{}''::jsonb
           );

    -- Cualquier otro error: revelar la causa real
    WHEN OTHERS THEN
      RETURN public.lumi_get_node(''HOME_DEFAULT'')
        || jsonb_build_object(
             ''ok'',    false,
             ''error'', ''dispatch_error: '' || v_fn || '' / '' || SQLSTATE || '' / '' || SQLERRM,
             ''state'', ''{}''::jsonb
           );
  END;

  RETURN coalesce(v_result, public.lumi_get_node(''HOME_DEFAULT''));
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('350', 'CREATE OR REPLACE FUNCTION public.lumi_go_back(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_source text := coalesce(p_params->>''source'', p_params->>''contentSource'', '''');
BEGIN
  CASE v_source
    WHEN ''fuente''    THEN RETURN public.lumi_open_fuente(p_params);
    WHEN ''sanctuary'' THEN RETURN public.lumi_open_sanctuary(p_params);
    ELSE                   RETURN public.lumi_go_home(p_params);
  END CASE;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('336', 'CREATE OR REPLACE FUNCTION public.lumi_feedback_helpful(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id     uuid;
  v_auth_user_id uuid;
  v_has_real_account boolean := false;
  v_session_id  uuid;
  v_resource_id uuid;
  v_run_id      uuid;
  v_node        jsonb;
  v_card        jsonb;
  v_result      jsonb;
BEGIN
  p_params      := public.lumi_normalize_params(p_params);
  v_user_id     := nullif(trim(p_params->>''user_id''), '''')::uuid;
  v_auth_user_id := auth.uid();
  v_session_id  := nullif(trim(p_params->>''session_id''), '''')::uuid;
  v_resource_id := nullif(trim(p_params->>''resource_id''), '''')::uuid;
  v_run_id      := nullif(trim(COALESCE(p_params->>''experience_run_id'', p_params->>''currentExperienceRunId'')), '''')::uuid;

  SELECT EXISTS (
    SELECT 1
    FROM auth.users au
    WHERE au.id = COALESCE(v_user_id, v_auth_user_id)
      AND NULLIF(TRIM(au.email), '''') IS NOT NULL
  )
  INTO v_has_real_account;

  IF v_run_id IS NOT NULL THEN
    v_result := public.lumi_complete_experience_run(v_run_id, ''me_dejo_un_poco_mejor'');

    IF NOT v_has_real_account THEN
      v_node := public.lumi_get_node(''REGISTRATION_PROMPT'');

      RETURN v_node || jsonb_build_object(
        ''ok'', true,
        ''code'', ''REGISTRATION_PROMPT'',
        ''content_type'', ''empty_presence'',
        ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
        ''state'', COALESCE(v_result->''state'', ''{}''::jsonb)
          || jsonb_build_object(
            ''contentSource'', ''lumi'',
            ''currentExperienceRunId'', v_run_id::text,
            ''showRegistrationPrompt'', true
          )
      );
    END IF;

    RETURN v_result;
  END IF;

  -- Legacy puro: sólo si no existe run.
  IF v_resource_id IS NULL THEN
    RETURN public.lumi_get_node(''HOME_DEFAULT'')
      || jsonb_build_object(''ok'', false, ''error'', ''missing_resource_for_feedback'', ''state'', ''{}''::jsonb);
  END IF;

  IF v_session_id IS NOT NULL THEN
    PERFORM public.gaia_submit_session_action(
      p_session_id         := v_session_id,
      p_chosen_resource_id := v_resource_id,
      p_feedback           := ''me_sirvio'',
      p_saved              := false
    );
  END IF;

  IF NOT v_has_real_account THEN
    v_node := public.lumi_get_node(''REGISTRATION_PROMPT'');

    RETURN v_node || jsonb_build_object(
      ''ok'', true,
      ''code'', ''REGISTRATION_PROMPT'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', jsonb_build_object(
        ''contentSource'', ''lumi'',
        ''currentResourceId'', v_resource_id::text,
        ''showRegistrationPrompt'', true
      )
    );
  END IF;

  v_card := public.gaia_get_resource_card(v_user_id, v_resource_id, v_session_id);
  v_node := public.lumi_get_node(''RESOURCE_FEEDBACK_HELPFUL'');

  RETURN jsonb_build_object(
    ''ok'', true,
    ''code'', ''RESOURCE_FEEDBACK_HELPFUL'',
    ''message'', COALESCE(v_node->>''message'', ''Me alegra que haya servido un poco.''),
    ''actions'', COALESCE(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', ''resource_card'',
    ''content'', COALESCE(v_card, ''{}''::jsonb) || jsonb_build_object(
      ''type'', ''resource_card'',
      ''resource_id'', v_resource_id::text,
      ''session_id'', COALESCE(v_session_id::text, ''''),
      ''is_from'', ''lumi''
    ),
    ''state'', jsonb_build_object(''currentResourceId'', v_resource_id::text, ''contentSource'', ''lumi'')
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('337', 'CREATE OR REPLACE FUNCTION public.lumi_feedback_reject(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_session_id  uuid;
  v_resource_id uuid;
  v_run_id      uuid;
  v_node        jsonb;
  v_reflection  text;
BEGIN
  p_params      := public.lumi_normalize_params(p_params);
  v_session_id  := nullif(trim(p_params->>''session_id''), '''')::uuid;
  v_resource_id := nullif(trim(p_params->>''resource_id''), '''')::uuid;
  v_run_id      := nullif(trim(COALESCE(p_params->>''experience_run_id'', p_params->>''currentExperienceRunId'')), '''')::uuid;

  IF v_run_id IS NOT NULL THEN
    RETURN public.lumi_complete_experience_run(v_run_id, ''no_era_para_mi'');
  END IF;

  -- Legacy puro: sólo si no existe run.
  IF v_resource_id IS NULL THEN
    RETURN public.lumi_get_node(''HOME_DEFAULT'')
      || jsonb_build_object(''ok'', false, ''error'', ''missing_resource_for_feedback'', ''state'', ''{}''::jsonb);
  END IF;

  IF v_session_id IS NOT NULL THEN
    PERFORM public.gaia_submit_session_action(
      p_session_id         := v_session_id,
      p_chosen_resource_id := v_resource_id,
      p_feedback           := ''no_me_sirvio'',
      p_saved              := false
    );
  END IF;

  v_node       := public.lumi_get_node(''RESOURCE_FEEDBACK_REJECT'');
  v_reflection := public.lumi_get_message(''reflection'', ''after_action'');

  RETURN jsonb_build_object(
    ''ok'', true,
    ''code'', ''RESOURCE_FEEDBACK_REJECT'',
    ''message'', COALESCE(v_reflection, v_node->>''message'', ''Entendido. Probemos otra cosa.''),
    ''actions'', COALESCE(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', ''empty_presence'',
    ''content'', jsonb_build_object(''type'', ''empty_presence''),
    ''state'', ''{}''::jsonb
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('339', 'CREATE OR REPLACE FUNCTION public.lumi_get_fuente_items(p_necesito text DEFAULT ''''::text, p_formato text DEFAULT ''''::text, p_duracion text DEFAULT ''''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_items             jsonb;
  v_count             integer := 0;
  v_max_mins          integer := 999;
  v_node              jsonb;
  v_message           text;
  v_filter_parts      text[] := ARRAY[]::text[];
  v_filter_label      text := '''';
  v_necesito_options  jsonb;
  v_format_options    jsonb;
  v_duration_options  jsonb;
  v_cap_need_label    text;
  v_filter_options    jsonb;
  v_filters_legacy    jsonb;
BEGIN
  p_necesito := COALESCE(NULLIF(trim(p_necesito), ''''), '''');
  p_formato  := COALESCE(NULLIF(trim(p_formato), ''''), '''');
  p_duracion := COALESCE(NULLIF(trim(p_duracion), ''''), '''');

  IF p_duracion <> '''' THEN
    v_max_mins := public.lumi_max_minutes(p_duracion::public.time_bucket);
    v_filter_parts := array_append(v_filter_parts, CASE p_duracion WHEN ''t2_5'' THEN ''hasta 5 min'' WHEN ''t5_15'' THEN ''5 a 15 min'' WHEN ''t15_plus'' THEN ''más de 15 min'' ELSE p_duracion END);
  END IF;

  IF p_necesito <> '''' THEN
    SELECT uc.short_label INTO v_cap_need_label
    FROM public.ui_copy uc
    WHERE uc.domain = ''capability'' AND uc.key = p_necesito AND uc.lang = ''es''
    LIMIT 1;
    v_filter_parts := array_append(v_filter_parts, COALESCE(v_cap_need_label, p_necesito));
  END IF;

  IF p_formato <> '''' THEN
    v_filter_parts := array_append(v_filter_parts, COALESCE((SELECT uc.short_label FROM public.ui_copy uc WHERE uc.domain = ''resource_format'' AND uc.key = p_formato AND uc.lang = ''es'' LIMIT 1), p_formato));
  END IF;

  v_filter_label := array_to_string(v_filter_parts, '' · '');

  SELECT jsonb_agg(jsonb_build_object(''value'', uc.key, ''label'', uc.short_label) ORDER BY uc.sort_order NULLS LAST, uc.key)
  INTO v_necesito_options
  FROM public.ui_copy uc
  WHERE uc.domain = ''capability'' AND uc.lang = ''es'' AND uc.short_label IS NOT NULL;

  SELECT jsonb_agg(jsonb_build_object(''value'', uc.key, ''label'', uc.short_label) ORDER BY uc.sort_order NULLS LAST, uc.key)
  INTO v_format_options
  FROM public.ui_copy uc
  WHERE uc.domain = ''resource_format'' AND uc.lang = ''es'';

  SELECT jsonb_agg(jsonb_build_object(''value'', uc.key, ''label'', uc.short_label) ORDER BY uc.sort_order NULLS LAST, uc.key)
  INTO v_duration_options
  FROM public.ui_copy uc
  WHERE uc.domain = ''time_bucket'' AND uc.lang = ''es'';

  v_filter_options := jsonb_build_object(''necesito'', COALESCE(v_necesito_options, ''[]''::jsonb), ''formato'', COALESCE(v_format_options, ''[]''::jsonb), ''duracion'', COALESCE(v_duration_options, ''[]''::jsonb));
  v_filters_legacy := jsonb_build_object(''necesito_options'', COALESCE(v_necesito_options, ''[]''::jsonb), ''format_options'', COALESCE(v_format_options, ''[]''::jsonb), ''duration_options'', COALESCE(v_duration_options, ''[]''::jsonb));

  SELECT jsonb_agg(
    jsonb_build_object(
      ''id'', e.id::text,
      ''action'', ''preview_experience'',
      ''value'', ''fuente'',
      ''source'', ''fuente'',
      ''experience_id'', e.id::text,
      ''resource_id'', r.id::text,
      ''title'', e.title,
      ''subtitle'', COALESCE((SELECT uc.short_label FROM public.ui_copy uc WHERE uc.domain = ''resource_format'' AND uc.key = r.format::text AND uc.lang = ''es'' LIMIT 1), r.format::text),
      ''format'', r.format::text,
      ''duration_min'', r.duration_min,
      ''author'', COALESCE(r.author, r.provider),
      ''why_now'', r.why_now,
      ''minimum_step'', r.minimum_step,
      ''capability_key'', e.expected_capability_key,
      ''editorial_status'', e.editorial_status,
      ''source_control'', r.source_control
    )
    ORDER BY CASE e.editorial_status WHEN ''core_mvp'' THEN 1 WHEN ''enrichment_mvp'' THEN 2 ELSE 9 END, e.priority ASC, r.duration_min ASC
  )
  INTO v_items
  FROM public.experiences e
  JOIN public.resources r ON r.id = e.primary_resource_id
  WHERE e.active = true
    AND e.editorial_status IN (''core_mvp'', ''enrichment_mvp'')
    AND r.is_active = true
    AND r.status = ''active''
    AND r.duration_min <= v_max_mins
    AND (p_necesito = '''' OR e.expected_capability_key = p_necesito)
    AND (p_formato = '''' OR r.format::text = p_formato);

  v_count := jsonb_array_length(COALESCE(v_items, ''[]''::jsonb));

  IF v_count = 0 THEN
    v_node := public.lumi_get_node(''FUENTE_EMPTY'');
    RETURN v_node || jsonb_build_object(
      ''ok'', true,
      ''code'', ''FUENTE_EMPTY'',
      ''content_type'', ''empty_presence'',
      ''content'', jsonb_build_object(''type'', ''empty_presence'', ''source'', ''fuente'', ''filter_options'', v_filter_options),
      ''filters'', v_filters_legacy,
      ''state'', jsonb_build_object(''contentSource'', ''fuente'')
    );
  END IF;

  v_message := CASE WHEN v_filter_label <> '''' THEN ''Explorando: '' || v_filter_label ELSE ''La Fuente — ayudas disponibles'' END;
  v_node := public.lumi_get_node(''FUENTE_DEFAULT'');

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''FUENTE_DEFAULT'',
    ''message'', v_message,
    ''content_type'', ''item_list'',
    ''content'', jsonb_build_object(''type'', ''item_list'', ''source'', ''fuente'', ''items'', COALESCE(v_items, ''[]''::jsonb), ''filter_options'', v_filter_options),
    ''filters'', v_filters_legacy,
    ''state'', jsonb_build_object(''contentSource'', ''fuente'')
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('340', 'CREATE OR REPLACE FUNCTION public.lumi_get_init_data(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_has_visited       boolean := false;
  v_sanctuary_count   integer := 0;
  v_days_since        integer := 0;
  v_session_count     integer := 0;
  v_is_anonymous      boolean := true;
  v_prompt_dismissed  boolean := false;
  v_reflection        text := null;
  v_show_register     boolean := false;
  v_first_name        text := null;
BEGIN
  SELECT
    COALESCE(u.has_visited, false),
    COALESCE(u.registration_prompt_dismissed, false),
    NULLIF(BTRIM(u.first_name), '''')
  INTO
    v_has_visited,
    v_prompt_dismissed,
    v_first_name
  FROM public.users u
  WHERE u.id = p_user_id;

  v_has_visited := COALESCE(v_has_visited, false);
  v_prompt_dismissed := COALESCE(v_prompt_dismissed, false);

  /*
    Criterio canónico MVP:
    - Cuenta real = auth.users.email no nulo / no vacío.
    - Usuario anónimo técnico = email nulo o vacío.
    No usar auth.users.is_anonymous como fuente de verdad de producto.
  */
  SELECT
    (NULLIF(TRIM(COALESCE(au.email, '''')), '''') IS NULL),
    COALESCE(
      v_first_name,
      NULLIF(BTRIM(au.raw_user_meta_data->>''first_name''), ''''),
      NULLIF(BTRIM(au.raw_user_meta_data->>''display_name''), ''''),
      NULLIF(BTRIM(au.raw_user_meta_data->>''name''), '''')
    )
  INTO
    v_is_anonymous,
    v_first_name
  FROM auth.users au
  WHERE au.id = p_user_id;

  v_is_anonymous := COALESCE(v_is_anonymous, true);

  SELECT count(*)
  INTO v_sanctuary_count
  FROM public.sanctuary_items si
  WHERE si.user_id = p_user_id
    AND si.experience_run_id IS NOT NULL;

  SELECT COALESCE(
    EXTRACT(day FROM (now() - max(s.created_at)))::integer,
    0
  )
  INTO v_days_since
  FROM public.sessions s
  WHERE s.user_id = p_user_id;

  SELECT count(*)
  INTO v_session_count
  FROM public.sessions s
  WHERE s.user_id = p_user_id
    AND s.mode = ''propose'';

  -- Momentos de reflejo sobrio — en orden de prioridad.
  IF v_session_count = 10 THEN
    v_reflection := ''Llevás un tiempo viniendo. El sistema nota que seguís.'';
  ELSIF v_sanctuary_count = 5 THEN
    v_reflection := ''Ya tenés cinco cosas guardadas. Vas construyendo algo tuyo.'';
  ELSIF v_has_visited AND v_sanctuary_count >= 1 AND v_days_since >= 3 THEN
    v_reflection := ''La última vez te llevaste algo. ¿Querés verlo o empezamos de nuevo?'';
  END IF;

  -- Señal de registro para usuarios sin cuenta real.
  IF v_is_anonymous AND NOT v_prompt_dismissed AND v_session_count >= 2 THEN
    v_show_register := true;
  END IF;

  RETURN jsonb_build_object(
    ''first_name'',              v_first_name,
    ''firstName'',               v_first_name,
    ''name'',                    v_first_name,
    ''has_visited'',             v_has_visited,
    ''sanctuary_count'',         v_sanctuary_count,
    ''days_since_last_session'', v_days_since,
    ''session_count'',           v_session_count,
    ''reflection_hint'',         v_reflection,
    ''is_anonymous'',            v_is_anonymous,
    ''show_register_prompt'',    v_show_register
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('351', 'CREATE OR REPLACE FUNCTION public.lumi_go_home(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id uuid;
  v_user_name text;
  v_sanctuary_count integer;
  v_node_code text;
  v_node jsonb;
  v_message text;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_user_id := NULLIF(trim(COALESCE(p_params->>''user_id'', '''')), '''')::uuid;

  IF v_user_id IS NOT NULL THEN
    SELECT COALESCE(NULLIF(trim(first_name), ''''), ''Pablo'')
    INTO v_user_name
    FROM public.users
    WHERE id = v_user_id;
  END IF;

  v_user_name := COALESCE(v_user_name, ''Pablo'');

  IF v_user_id IS NOT NULL THEN
    SELECT COUNT(*)
    INTO v_sanctuary_count
    FROM public.sanctuary_items
    WHERE user_id = v_user_id
      AND experience_run_id IS NOT NULL;
  ELSE
    v_sanctuary_count := 0;
  END IF;

  v_node_code := CASE
    WHEN v_sanctuary_count > 0 THEN ''HOME_RETURNING''
    ELSE ''HOME_DEFAULT''
  END;

  v_node := public.lumi_get_node(v_node_code);

  v_message := COALESCE(v_node->>''message'', '''');

  -- Personalización mínima y segura.
  v_message := replace(v_message, ''Pablo'', v_user_name);

  RETURN jsonb_build_object(
    ''ok'', true,
    ''code'', v_node_code,
    ''title'', v_node->>''title'',
    ''module'', COALESCE(v_node->>''module'', ''home''),
    ''node_type'', v_node->>''node_type'',
    ''moment_type'', v_node->>''moment_type'',
    ''message'', v_message,
    ''actions'', COALESCE(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', COALESCE(v_node->>''content_type'', ''empty_presence''),
    ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'', ''source'', ''home'')),
    ''metadata'', COALESCE(v_node->''metadata'', ''{}''::jsonb),
    ''state'', public.lumi_clear_conversation_state(
      ''lumi'',
      ''#7860E0'',
      '''',
      ''''
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('353', 'CREATE OR REPLACE FUNCTION public.lumi_mode_presence(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_node    jsonb;
  v_message text;
BEGIN
  v_node := public.lumi_get_node(''HOME_PRESENCE'');

  -- Asimetría enriquecedora: a veces LUMI te abraza, a veces te
  -- ofrece una pausa de sabiduría.
  IF random() < 0.5 THEN
    v_message := public.lumi_get_message(''support'', ''companion'');
  ELSE
    v_message := public.lumi_get_message(''quote'', ''wisdom'');
  END IF;

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         ''HOME_PRESENCE'',
    ''message'',      coalesce(v_message, v_node->>''message'', ''Acá estoy.''),
    ''actions'',      coalesce(v_node->''actions'',
                             jsonb_build_array(
                               jsonb_build_object(''label'', ''Volver al inicio'',
                                                  ''action'', ''go_home'')
                             )),
    ''content_type'', ''empty_presence'',
    ''content'',      jsonb_build_object(''type'', ''empty_presence''),
    ''state'',        jsonb_build_object(
                      ''contentSource'', '''',
                      ''moduleColor'',   ''#7860E0''
                    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('354', 'CREATE OR REPLACE FUNCTION public.lumi_mode_presence(p_user_id_text text)
