INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('361', 'CREATE OR REPLACE FUNCTION public.lumi_open_faro_journey(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE v_user_id uuid; v_id uuid; v_title text; v_status text; v_events jsonb; v_node jsonb;
BEGIN
 p_params:=public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb)); v_user_id:=NULLIF(trim(p_params->>''user_id''),'''')::uuid;
 v_id:=NULLIF(trim(COALESCE(NULLIF(p_params->>''value'',''''),p_params->>''resource_id'',p_params->>''user_area_faro_id'')),'''')::uuid;
 SELECT COALESCE(uc.short_label,uaf.faro_text,uaf.faro_key),uaf.status INTO v_title,v_status FROM public.user_area_faros uaf LEFT JOIN public.ui_copy uc ON uc.domain=''faro'' AND uc.lang=''es'' AND uc.key=uaf.faro_key WHERE uaf.id=v_id AND uaf.user_id=v_user_id;
 SELECT COALESCE(jsonb_agg(jsonb_build_object(''id'',er.id::text,''date'',er.started_at,''title'',COALESCE(e.title,''Experiencia vivida''),
  ''selected_capability_key'',COALESCE(er.selected_capability_key,''''),''perceived_capability_key'',COALESCE(er.perceived_capability_key,''''),
  ''help_signal'',COALESCE(er.help_signal,''''),''reflection_text'',COALESCE(er.reflection_text,'''')) ORDER BY er.started_at DESC),''[]''::jsonb)
 INTO v_events FROM public.experience_runs er LEFT JOIN public.experiences e ON e.id=er.experience_id WHERE er.user_id=v_user_id AND er.user_area_faro_id=v_id AND er.hemisphere_key=''H2'';
 v_node:=public.lumi_get_node(''SANCTUARY_JOURNEY_DETAIL'');
 RETURN v_node||jsonb_build_object(''ok'',true,''message'',''Este es el camino que fuiste recorriendo hacia "''||COALESCE(v_title,''tu Faro'')||''".'',
  ''actions'',jsonb_build_array(jsonb_build_object(''label'',''Volver a recorridos'',''action'',''open_sanctuary_journeys'',''variant'',''ghost'')),
  ''content_type'',''activity_detail'',''content'',jsonb_build_object(''type'',''activity_detail'',''detail_kind'',''faro_journey'',''title'',v_title,''status'',v_status,''events'',v_events,''user_area_faro_id'',v_id::text),
  ''state'',jsonb_build_object(''contentSource'',''sanctuary'',''currentItemId'',v_id::text));
END; $function$
');

