INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('365', 'CREATE OR REPLACE FUNCTION public.lumi_open_note_editor(p_user_id_text text, p_resource_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id     uuid;
  v_resource_id uuid;
  v_node        jsonb;
  v_item        record;
BEGIN
  IF nullif(trim(coalesce(p_user_id_text, '''')), '''') IS NULL THEN
    RETURN public.lumi_get_node(''SANCTUARY_WITH_ITEMS'');
  END IF;

  IF nullif(trim(both '''''''' FROM trim(coalesce(p_resource_id_text, ''''))), '''') IS NULL THEN
    RETURN public.lumi_get_node(''SANCTUARY_WITH_ITEMS'');
  END IF;

  v_user_id     := nullif(trim(p_user_id_text), '''')::uuid;
  v_resource_id := nullif(
    trim(both '''''''' FROM trim(coalesce(p_resource_id_text, ''''))), ''''
  )::uuid;

  SELECT
    si.id           AS sanctuary_item_id,
    si.note,
    si.life_area_key AS area,   -- fix: era si.area
    r.title
  INTO v_item
  FROM public.sanctuary_items si
  JOIN public.resources r ON r.id = si.resource_id
  WHERE si.user_id     = v_user_id
    AND si.resource_id = v_resource_id
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN public.lumi_get_node(''SANCTUARY_WITH_ITEMS'');
  END IF;

  v_node := public.lumi_get_node(''SANCTUARY_NOTE'');

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         ''SANCTUARY_NOTE'',
    ''message'',      coalesce(v_node->>''message'', ''Podés dejar una nota para vos.''),
    ''actions'',      coalesce(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', ''note_editor'',
    ''content'',      jsonb_build_object(
      ''type'',               ''note_editor'',
      ''resource_id'',        v_resource_id::text,
      ''sanctuary_item_id'',  coalesce(v_item.sanctuary_item_id::text, ''''),
      ''title'',              coalesce(v_item.title, ''Recurso''),
      ''current_note'',       coalesce(v_item.note, ''''),
      ''current_area'',       coalesce(v_item.area, '''')
    ),
    ''state'',        jsonb_build_object(
      ''contentSource'', ''sanctuary'',
      ''moduleColor'',   ''#B88820''
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('379', 'CREATE OR REPLACE FUNCTION public.lumi_remove_from_sanctuary(p_user_id_text text, p_sanctuary_item_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id uuid;
  v_sanctuary_item_id uuid;
begin
  v_user_id := nullif(trim(p_user_id_text), '''')::uuid;

  v_sanctuary_item_id := nullif(
    trim(both '''''''' from trim(coalesce(p_sanctuary_item_id_text, ''''))),
    ''''
  )::uuid;

  delete from public.sanctuary_items
  where id = v_sanctuary_item_id
    and user_id = v_user_id;

  return public.lumi_get_sanctuary(v_user_id);
end;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('366', 'CREATE OR REPLACE FUNCTION public.lumi_open_resource(p_user_id_text text, p_resource_id_text text, p_source text DEFAULT ''fuente''::text, p_session_id_text text DEFAULT ''''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id uuid;
  v_resource_id uuid;
  v_session_id uuid;
  v_session_text text;
  v_card jsonb;
  v_node_code text;
  v_node jsonb;
begin
  v_user_id := nullif(trim(p_user_id_text), '''')::uuid;
  v_resource_id := nullif(trim(p_resource_id_text), '''')::uuid;
  v_session_text := trim(both '''''''' from trim(coalesce(p_session_id_text, '''')));
  v_session_id := case when v_session_text = '''' then null else v_session_text::uuid end;

  -- Registrar apertura (solo si hay sesión). reopened diferido: siempre ''opened''.
  IF v_session_id IS NOT NULL AND v_resource_id IS NOT NULL THEN
    PERFORM public.gaia_submit_session_action(
      p_session_id         := v_session_id,
      p_chosen_resource_id := v_resource_id,
      p_feedback           := NULL,
      p_saved              := false,
      p_action             := ''opened''
    );
  END IF;

  v_card := public.gaia_get_resource_card(v_user_id, v_resource_id, v_session_id);

  v_node_code := case
    when p_source = ''lumi'' then ''RESOURCE_FROM_LUMI''
    when p_source = ''sanctuary'' then ''RESOURCE_FROM_SANCTUARY''
    else ''RESOURCE_FROM_FUENTE''
  end;
  v_node := public.lumi_get_node(v_node_code);

  return jsonb_build_object(
    ''ok'', true,
    ''code'', v_node_code,
    ''message'', coalesce(v_card->>''lumi_context'', v_node->>''message''),
    ''actions'', coalesce(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', ''resource_card'',
    ''content'', coalesce(v_card, ''{}''::jsonb) ||
      jsonb_build_object(''type'', ''resource_card'', ''resource_id'', v_resource_id::text,
        ''session_id'', coalesce(v_session_id::text, ''''), ''is_from'', p_source),
    ''state'', jsonb_build_object(
      ''currentResourceId'', v_resource_id::text,
      ''resourceSourceKind'', coalesce(v_card->>''source_kind'', ''external_url''),
      ''activeUrl'', coalesce(v_card->>''url'', ''''),
      ''contentSource'', p_source)
  );
end;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('368', 'CREATE OR REPLACE FUNCTION public.lumi_open_resource_viewer(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id     uuid;
  v_session_id  uuid;
  v_resource_id uuid;
  v_run_id      uuid;
  v_node        jsonb;
  v_resource    record;
  v_source      text;
  v_source_kind text;
BEGIN
  p_params      := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));
  v_user_id     := NULLIF(TRIM(COALESCE(p_params->>''user_id'', '''')), '''')::uuid;
  v_session_id  := NULLIF(TRIM(COALESCE(p_params->>''session_id'', '''')), '''')::uuid;
  v_resource_id := NULLIF(TRIM(COALESCE(p_params->>''resource_id'', '''')), '''')::uuid;
  v_run_id      := NULLIF(TRIM(COALESCE(p_params->>''experience_run_id'', p_params->>''currentExperienceRunId'', '''')), '''')::uuid;
  v_source      := COALESCE(NULLIF(TRIM(COALESCE(p_params->>''source'', '''')), ''''), ''lumi'');

  IF v_resource_id IS NULL THEN
    RETURN public.lumi_get_node(''HOME_DEFAULT'')
      || jsonb_build_object(
        ''ok'', false,
        ''error'', ''resource_id_requerido'',
        ''state'', ''{}''::jsonb
      );
  END IF;

  SELECT
    r.id,
    r.title,
    r.url,
    r.source_kind,
    r.format,
    r.duration_min,
    r.metadata
  INTO v_resource
  FROM public.resources r
  WHERE r.id = v_resource_id;

  IF NOT FOUND THEN
    RETURN public.lumi_get_node(''HOME_DEFAULT'')
      || jsonb_build_object(
        ''ok'', false,
        ''error'', ''resource_not_found'',
        ''state'', ''{}''::jsonb
      );
  END IF;

  v_source_kind := COALESCE(NULLIF(TRIM(COALESCE(v_resource.source_kind, '''')), ''''), ''external_url'');

  IF v_session_id IS NOT NULL THEN
    BEGIN
      PERFORM public.gaia_submit_session_action(
        p_session_id         := v_session_id,
        p_chosen_resource_id := v_resource_id,
        p_feedback           := NULL,
        p_saved              := false,
        p_action             := ''opened''
      );
    EXCEPTION WHEN OTHERS THEN
      NULL;
    END;
  END IF;

  v_node := public.lumi_get_node(''RESOURCE_VIEWER_ACTIVE'');

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         ''RESOURCE_VIEWER_ACTIVE'',
    ''message'',      COALESCE(v_node->>''message'', ''Tomá el tiempo que necesitás.''),
    ''actions'',      COALESCE(v_node->''actions'', jsonb_build_array(
                      jsonb_build_object(
                        ''label'', ''Listo'',
                        ''value'', '''',
                        ''action'', ''close_resource_viewer''
                      )
                    )),
    ''content_type'', ''resource_viewer'',
    ''content'',      jsonb_build_object(
                      ''type'',              ''resource_viewer'',
                      ''title'',             COALESCE(v_resource.title, ''''),
                      ''url'',               COALESCE(v_resource.url, ''''),
                      ''activeUrl'',         COALESCE(v_resource.url, ''''),
                      ''source_kind'',       v_source_kind,
                      ''format'',            COALESCE(v_resource.format::text, ''''),
                      ''duration_min'',      COALESCE(v_resource.duration_min, 0),
                      ''resource_id'',       v_resource_id::text,
                      ''experience_run_id'', COALESCE(v_run_id::text, ''''),
                      ''run_id'',            COALESCE(v_run_id::text, ''''),
                      ''source'',            v_source,
                      ''metadata'',          COALESCE(v_resource.metadata, ''{}''::jsonb)
                    ),
    ''state'',        jsonb_build_object(
                      ''currentResourceId'',      v_resource_id::text,
                      ''currentExperienceRunId'', COALESCE(v_run_id::text, ''''),
                      ''resourceSourceKind'',     v_source_kind,
                      ''activeUrl'',              COALESCE(v_resource.url, ''''),
                      ''contentSource'',          v_source
                    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('369', 'CREATE OR REPLACE FUNCTION public.lumi_open_sanctuary(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE v_user_id uuid; v_has_faros bool; v_has_journeys bool; v_has_saved bool; v_has_reflections bool; v_actions jsonb:=''[]''; v_items jsonb:=''[]''; v_message text; v_node jsonb;
BEGIN
 p_params:=public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb)); v_user_id:=NULLIF(trim(p_params->>''user_id''),'''')::uuid;
 SELECT EXISTS(SELECT 1 FROM public.user_area_faros WHERE user_id=v_user_id),
        EXISTS(SELECT 1 FROM public.experience_runs WHERE user_id=v_user_id AND hemisphere_key=''H2'' AND user_area_faro_id IS NOT NULL),
        EXISTS(SELECT 1 FROM public.sanctuary_items WHERE user_id=v_user_id),
        EXISTS(SELECT 1 FROM public.sanctuary_items si LEFT JOIN public.experience_runs er ON er.id=si.experience_run_id WHERE si.user_id=v_user_id AND COALESCE(NULLIF(si.note,''''),NULLIF(si.reflection_text,''''),NULLIF(er.reflection_text,'''')) IS NOT NULL)
          OR EXISTS(SELECT 1 FROM public.user_area_faros WHERE user_id=v_user_id AND NULLIF(close_reflection,'''') IS NOT NULL)
 INTO v_has_faros,v_has_journeys,v_has_saved,v_has_reflections;

 IF v_has_faros THEN v_actions:=v_actions||jsonb_build_array(jsonb_build_object(''label'',''Mi territorio y mis Faros'',''action'',''open_faros'',''variant'',''outline'')); END IF;
 IF v_has_journeys THEN v_actions:=v_actions||jsonb_build_array(jsonb_build_object(''label'',''Mis recorridos'',''action'',''open_sanctuary_journeys'',''variant'',''outline'')); END IF;
 IF v_has_saved THEN v_actions:=v_actions||jsonb_build_array(jsonb_build_object(''label'',''Guardado para mí'',''action'',''open_sanctuary_saved'',''variant'',''outline'')); END IF;
 IF v_has_reflections THEN v_actions:=v_actions||jsonb_build_array(jsonb_build_object(''label'',''Notas y reflexiones'',''action'',''open_sanctuary_reflections'',''variant'',''outline'')); END IF;

 IF NOT(v_has_faros OR v_has_journeys OR v_has_saved OR v_has_reflections) THEN
  v_message:=''Este espacio irá creciendo con aquello que tenga valor en tu camino.'';
  v_actions:=jsonb_build_array(jsonb_build_object(''label'',''Elegir mis primeros Faros'',''action'',''open_faros'',''variant'',''solid''),jsonb_build_object(''label'',''Volver'',''action'',''go_home'',''variant'',''ghost''));
 ELSE
  v_message:=concat_ws('' '',CASE WHEN v_has_faros THEN ''Tus Faros siguen dando forma a tu territorio.'' END,CASE WHEN v_has_journeys THEN ''También podemos volver sobre lo que venís recorriendo.'' END,CASE WHEN v_has_saved THEN ''Hay experiencias que decidiste conservar.'' END,CASE WHEN v_has_reflections THEN ''Y palabras que fuiste dejando en el camino.'' END);
  SELECT COALESCE(jsonb_agg(obj ORDER BY ord),''[]''::jsonb) INTO v_items FROM (
   (SELECT 1 ord,jsonb_build_object(''id'',uaf.id::text,''title'',COALESCE(uc.short_label,uaf.faro_text,uaf.faro_key),''subtitle'',''Faro activo'',''action'',''open_faro_journey'') obj
    FROM public.user_area_faros uaf LEFT JOIN public.ui_copy uc ON uc.domain=''faro'' AND uc.lang=''es'' AND uc.key=uaf.faro_key
    WHERE uaf.user_id=v_user_id AND uaf.status=''active'' ORDER BY uaf.updated_at DESC LIMIT 1)
   UNION ALL
   (SELECT 2 ord,jsonb_build_object(''id'',si.id::text,''title'',COALESCE(e.title,r.title,''Experiencia guardada''),''subtitle'',''Guardado para vos'',''action'',''open_sanctuary_item'') obj
    FROM public.sanctuary_items si LEFT JOIN public.experience_runs er ON er.id=si.experience_run_id LEFT JOIN public.experiences e ON e.id=COALESCE(si.experience_id,er.experience_id) LEFT JOIN public.resources r ON r.id=COALESCE(si.resource_id,er.resource_id,e.primary_resource_id)
    WHERE si.user_id=v_user_id ORDER BY si.created_at DESC LIMIT 1)
  ) q;
 END IF;
 v_node:=public.lumi_get_node(''SANCTUARY_HOME'');
 RETURN v_node||jsonb_build_object(''ok'',true,''code'',''SANCTUARY_HOME'',''message'',v_message,''actions'',v_actions,
  ''content_type'',CASE WHEN jsonb_array_length(v_items)>0 THEN ''item_list'' ELSE ''empty_presence'' END,
  ''content'',CASE WHEN jsonb_array_length(v_items)>0 THEN jsonb_build_object(''type'',''item_list'',''source'',''sanctuary_home'',''items'',v_items) ELSE jsonb_build_object(''type'',''empty_presence'',''source'',''sanctuary_home'') END,
  ''state'',jsonb_build_object(''contentSource'',''sanctuary'',''moduleColor'',''#B88820''));
END; $function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('370', 'CREATE OR REPLACE FUNCTION public.lumi_open_sanctuary_item(p_params jsonb)
