INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('381', 'CREATE OR REPLACE FUNCTION public.lumi_resource_viewer_active(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_source_kind text;
  v_resource_id uuid;
  v_user_id     uuid;
  v_source      text;
  v_session_id  uuid;
  v_run_id      uuid;
  v_result      jsonb;
  v_resource    record;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_source_kind := COALESCE(NULLIF(TRIM(COALESCE(p_params->>''source_kind'', '''')), ''''), ''external_url'');
  v_resource_id := NULLIF(TRIM(COALESCE(p_params->>''resource_id'', '''')), '''')::uuid;
  v_user_id     := NULLIF(TRIM(COALESCE(p_params->>''user_id'', '''')), '''')::uuid;
  v_source      := COALESCE(NULLIF(TRIM(COALESCE(p_params->>''source'', '''')), ''''), ''lumi'');
  v_session_id  := NULLIF(TRIM(COALESCE(p_params->>''session_id'', '''')), '''')::uuid;
  v_run_id      := NULLIF(TRIM(COALESCE(p_params->>''experience_run_id'', p_params->>''currentExperienceRunId'', '''')), '''')::uuid;

  IF v_session_id IS NOT NULL AND v_resource_id IS NOT NULL THEN
    BEGIN
      PERFORM public.gaia_submit_session_action(
        p_session_id         := v_session_id,
        p_chosen_resource_id := v_resource_id,
        p_feedback           := NULL,
        p_saved              := false,
        p_action             := ''opened''
      );
    EXCEPTION WHEN OTHERS THEN
      NULL;
    END;
  END IF;

  v_result := public.lumi_resource_viewer_active(v_source_kind);

  IF v_resource_id IS NOT NULL THEN
    SELECT
      r.title,
      r.url,
      r.source_kind,
      r.format,
      r.duration_min,
      r.metadata
    INTO v_resource
    FROM public.resources r
    WHERE r.id = v_resource_id;

    IF FOUND THEN
      v_source_kind := COALESCE(NULLIF(TRIM(COALESCE(v_resource.source_kind, '''')), ''''), v_source_kind, ''external_url'');

      v_result := jsonb_set(
        v_result,
        ''{content}'',
        COALESCE(v_result->''content'', ''{}''::jsonb)
        || jsonb_build_object(
             ''type'',              ''resource_viewer'',
             ''title'',             COALESCE(v_resource.title, ''''),
             ''url'',               COALESCE(v_resource.url, ''''),
             ''activeUrl'',         COALESCE(v_resource.url, ''''),
             ''source_kind'',       v_source_kind,
             ''format'',            COALESCE(v_resource.format::text, ''''),
             ''duration_min'',      COALESCE(v_resource.duration_min, 0),
             ''resource_id'',       v_resource_id::text,
             ''experience_run_id'', COALESCE(v_run_id::text, ''''),
             ''run_id'',            COALESCE(v_run_id::text, ''''),
             ''source'',            v_source,
             ''metadata'',          COALESCE(v_resource.metadata, ''{}''::jsonb)
           )
      );

      v_result := jsonb_set(
        v_result,
        ''{state}'',
        COALESCE(v_result->''state'', ''{}''::jsonb)
        || jsonb_build_object(
             ''currentResourceId'',      v_resource_id::text,
             ''currentExperienceRunId'', COALESCE(v_run_id::text, ''''),
             ''activeUrl'',              COALESCE(v_resource.url, ''''),
             ''resourceSourceKind'',     v_source_kind,
             ''contentSource'',          v_source
           )
      );
    END IF;
  END IF;

  RETURN v_result;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('382', 'CREATE OR REPLACE FUNCTION public.lumi_resource_viewer_active(p_content_type text DEFAULT ''resource_viewer''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_node        jsonb;
  v_source_kind text;
BEGIN
  v_source_kind := COALESCE(NULLIF(TRIM(COALESCE(p_content_type, '''')), ''''), ''external_url'');

  IF v_source_kind = ''resource_viewer'' THEN
    v_source_kind := ''external_url'';
  END IF;

  v_node := public.lumi_get_node(''RESOURCE_VIEWER_ACTIVE'');

  RETURN v_node
    || jsonb_build_object(
      ''content_type'', ''resource_viewer'',
      ''content'', jsonb_build_object(
        ''type'',        ''resource_viewer'',
        ''source_kind'', v_source_kind
      )
    );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('384', 'CREATE OR REPLACE FUNCTION public.lumi_restore_node(p_user_id_text text, p_code text, p_context jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_source text := coalesce(p_context->>''source'', '''');
  v_resource_id text := coalesce(p_context->>''resource_id'', '''');
  v_session_id text := coalesce(p_context->>''session_id'', '''');
  v_sanctuary_item_id text := coalesce(p_context->>''sanctuary_item_id'', '''');
begin
  if p_code = ''SANCTUARY_DETAIL'' and v_sanctuary_item_id <> '''' then
    return public.lumi_open_sanctuary_item(
      p_user_id_text,
      v_sanctuary_item_id
    );
  end if;

  if p_code in (
    ''RESOURCE_FROM_LUMI'',
    ''RESOURCE_FROM_FUENTE'',
    ''RESOURCE_FROM_SANCTUARY''
  ) and v_resource_id <> '''' then
    return public.lumi_open_resource(
      p_user_id_text,
      v_resource_id,
      v_source,
      v_session_id
    );
  end if;

  return public.lumi_get_node(p_code);
end;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('386', 'CREATE OR REPLACE FUNCTION public.lumi_save_faro(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id uuid;
  v_area_text text;
  v_area public.life_area;
  v_faro_text text;
  v_faro_key text;
BEGIN
  p_params := public.lumi_normalize_params(p_params);

  v_user_id := NULLIF(trim(p_params->>''user_id''), '''')::uuid;
  v_area_text := NULLIF(trim(COALESCE(p_params->>''area'', '''')), '''');
  v_faro_text := COALESCE(p_params->>''faro_text'', '''');
  v_faro_key := NULLIF(trim(COALESCE(p_params->>''faro_key'', '''')), '''');

  IF v_user_id IS NULL OR v_area_text IS NULL THEN
    RETURN jsonb_build_object(''ok'', false, ''error'', ''missing_user_id_or_area'');
  END IF;

  BEGIN
    v_area := v_area_text::public.life_area;
  EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(''ok'', false, ''error'', ''invalid_area: '' || v_area_text);
  END;

  IF v_faro_key IS NOT NULL AND trim(v_faro_text) = '''' THEN
    SELECT uc.short_label
    INTO v_faro_text
    FROM public.ui_copy uc
    WHERE uc.domain = ''faro''
      AND uc.lang = ''es''
      AND uc.key = v_faro_key
    LIMIT 1;
  END IF;

  IF trim(v_faro_text) = '''' AND v_faro_key IS NULL THEN
    DELETE FROM public.user_area_faros
    WHERE user_id = v_user_id
      AND area = v_area;
  ELSE
    INSERT INTO public.user_area_faros (
      user_id,
      area,
      faro_text,
      faro_key,
      updated_at
    )
    VALUES (
      v_user_id,
      v_area,
      trim(COALESCE(v_faro_text, '''')),
      v_faro_key,
      now()
    )
    ON CONFLICT (user_id, area)
    DO UPDATE SET
      faro_text = excluded.faro_text,
      faro_key = excluded.faro_key,
      updated_at = now();
  END IF;

  RETURN jsonb_build_object(''ok'', true, ''state'', ''{}''::jsonb);
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('387', 'CREATE OR REPLACE FUNCTION public.lumi_save_note(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id           uuid;
  v_sanctuary_item_id uuid;
  v_resource_id       uuid;
  v_note              text;
  v_area_text         text;
BEGIN
  p_params := COALESCE(p_params, ''{}''::jsonb);

  v_user_id := NULLIF(TRIM(COALESCE(p_params->>''user_id'', '''')), '''')::uuid;

  v_sanctuary_item_id := NULLIF(
    TRIM(BOTH '''''''' FROM TRIM(COALESCE(p_params->>''sanctuary_item_id'', ''''))),
    ''''
  )::uuid;

  v_resource_id := NULLIF(
    TRIM(BOTH '''''''' FROM TRIM(COALESCE(p_params->>''resource_id'', ''''))),
    ''''
  )::uuid;

  v_note      := COALESCE(p_params->>''note'', '''');
  v_area_text := NULLIF(TRIM(COALESCE(p_params->>''area'', '''')), '''');

  IF v_user_id IS NULL THEN
    RETURN public.lumi_open_sanctuary(''{}''::jsonb);
  END IF;

  IF v_sanctuary_item_id IS NOT NULL THEN
    UPDATE public.sanctuary_items
    SET note          = NULLIF(v_note, ''''),
        life_area_key = v_area_text,
        updated_at    = now()
    WHERE id = v_sanctuary_item_id
      AND user_id = v_user_id
      AND experience_run_id IS NOT NULL;

    RETURN public.lumi_open_sanctuary_item(
      v_user_id::text,
      v_sanctuary_item_id::text
    );
  END IF;

  -- Fallback tolerante: si viene resource_id, busca un ítem canónico reciente.
  IF v_resource_id IS NOT NULL THEN
    SELECT si.id
    INTO v_sanctuary_item_id
    FROM public.sanctuary_items si
    JOIN public.experience_runs er
      ON er.id = si.experience_run_id
    LEFT JOIN public.experiences e
      ON e.id = COALESCE(si.experience_id, er.experience_id)
    WHERE si.user_id = v_user_id
      AND si.experience_run_id IS NOT NULL
      AND COALESCE(si.resource_id, er.resource_id, e.primary_resource_id) = v_resource_id
    ORDER BY si.updated_at DESC NULLS LAST, si.created_at DESC
    LIMIT 1;

    IF v_sanctuary_item_id IS NOT NULL THEN
      UPDATE public.sanctuary_items
      SET note          = NULLIF(v_note, ''''),
          life_area_key = v_area_text,
          updated_at    = now()
      WHERE id = v_sanctuary_item_id
        AND user_id = v_user_id;

      RETURN public.lumi_open_sanctuary_item(
        v_user_id::text,
        v_sanctuary_item_id::text
      );
    END IF;
  END IF;

  RETURN public.lumi_open_sanctuary(
    jsonb_build_object(''user_id'', v_user_id::text)
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('388', 'CREATE OR REPLACE FUNCTION public.lumi_save_to_sanctuary(p_user_id_text text, p_resource_id_text text, p_session_id_text text DEFAULT ''''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_node jsonb;
BEGIN
  v_node := public.lumi_get_node(''SANCTUARY_SAVE_REQUIRES_EXPERIENCE'');
  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''SANCTUARY_SAVE_REQUIRES_EXPERIENCE'',
    ''content_type'', ''empty_presence'',
    ''content'', jsonb_build_object(''type'', ''empty_presence'', ''source'', ''sanctuary''),
    ''state'', jsonb_build_object(''contentSource'', ''sanctuary'', ''moduleColor'', ''#B88820'')
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('389', 'CREATE OR REPLACE FUNCTION public.lumi_save_to_sanctuary(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_run_id             uuid;
  v_note               text;
  v_user_id            uuid;
  v_result             jsonb;
  v_is_anonymous       boolean;
  v_dismissed          boolean;
  v_node               jsonb;
  v_sanctuary_item_id  uuid;
BEGIN
  p_params := COALESCE(p_params, ''{}''::jsonb);

  v_run_id := NULLIF(TRIM(COALESCE(
    p_params->>''experience_run_id'',
    p_params->>''currentExperienceRunId'',
    ''''
  )), '''')::uuid;

  v_note := NULLIF(TRIM(COALESCE(p_params->>''note'', '''')), '''');

  v_user_id := NULLIF(TRIM(COALESCE(p_params->>''user_id'', '''')), '''')::uuid;

  IF v_run_id IS NULL THEN
    v_node := public.lumi_get_node(''SANCTUARY_SAVE_REQUIRES_EXPERIENCE'');

    RETURN v_node || jsonb_build_object(
      ''ok'', true,
      ''code'', ''SANCTUARY_SAVE_REQUIRES_EXPERIENCE'',
      ''content_type'', ''empty_presence'',
      ''content'', jsonb_build_object(''type'', ''empty_presence'', ''source'', ''sanctuary''),
      ''state'', jsonb_build_object(
        ''contentSource'', ''sanctuary'',
        ''moduleColor'', ''#B88820''
      )
    );
  END IF;

  v_result := public.lumi_save_experience_to_sanctuary(
    p_run_id := v_run_id,
    p_note := v_note
  );

  SELECT si.id, si.user_id
  INTO v_sanctuary_item_id, v_user_id
  FROM public.sanctuary_items si
  WHERE si.experience_run_id = v_run_id
  ORDER BY si.created_at DESC NULLS LAST
  LIMIT 1;

  IF v_sanctuary_item_id IS NOT NULL AND v_user_id IS NOT NULL THEN
    /*
      Canon MVP:
      Tras guardar, abrir directamente el detalle del ítem guardado.
      Así "Agregar nota" opera sobre currentSanctuaryItemId real,
      no sobre una lista ni un estado ambiguo.
    */
    v_result := public.lumi_open_sanctuary_item(
      v_user_id::text,
      v_sanctuary_item_id::text
    );

    RETURN v_result || jsonb_build_object(
      ''state'',
      COALESCE(v_result->''state'', ''{}''::jsonb) || jsonb_build_object(
        ''currentSanctuaryItemId'', v_sanctuary_item_id::text,
        ''currentExperienceRunId'', v_run_id::text,
        ''contentSource'', ''sanctuary'',
        ''moduleColor'', ''#B88820''
      )
    );
  END IF;

  /*
    Fallback conservador: si por alguna razón no encontramos item,
    devolver la respuesta original del guardado.
  */
  IF v_user_id IS NOT NULL THEN
    SELECT COALESCE(au.is_anonymous, false)
    INTO v_is_anonymous
    FROM auth.users au
    WHERE au.id = v_user_id;

    SELECT COALESCE(u.registration_prompt_dismissed, false)
    INTO v_dismissed
    FROM public.users u
    WHERE u.id = v_user_id;

    IF v_is_anonymous AND NOT v_dismissed THEN
      v_result := v_result || jsonb_build_object(
        ''show_register_prompt'', true,
        ''register_hint'', ''Para que no pierdas lo que guardaste, podés crear una cuenta.''
      );
    END IF;
  END IF;

  RETURN v_result;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('391', 'CREATE OR REPLACE FUNCTION public.lumi_share_light(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_res jsonb;
  v_content jsonb;
  v_state jsonb;
  v_token text;
  v_share_light_id text;
  v_share_path text;
  v_node jsonb;
BEGIN
  v_res := public.lumi_share_light__core(p_params);

  IF COALESCE((v_res->>''ok'')::boolean, false) IS NOT TRUE THEN
    RETURN v_res;
  END IF;

  v_content := COALESCE(v_res->''content'', ''{}''::jsonb);
  v_state   := COALESCE(v_res->''state'', ''{}''::jsonb);

  v_token := NULLIF(v_content->>''share_token'', '''');
  v_share_light_id := COALESCE(
    NULLIF(v_content->>''share_light_id'', ''''),
    NULLIF(v_state->>''currentShareLightId'', '''')
  );

  IF v_token IS NOT NULL THEN
    v_share_path := ''/?share_light='' || v_token;
  END IF;

  v_content := v_content || jsonb_build_object(
    ''type'', ''share_light_editor'',
    ''source'', ''share_light'',
    ''editor_title'', COALESCE(NULLIF(v_content->>''editor_title'', ''''), ''Compartir luz''),
    ''editor_subtitle'', ''Podés ajustar el texto antes de compartirlo.'',
    ''editor_helper'', ''LUMEN nunca incluye tu nota personal, tu estado ni tu Santuario privado.'',
    ''privacy_hint'', ''Tu Santuario sigue siendo privado''
  );

  IF v_token IS NOT NULL THEN
    v_content := v_content || jsonb_build_object(
      ''share_token'', v_token,
      ''share_path'', v_share_path,
      ''share_url'', ''''
    );
    v_state := v_state || jsonb_build_object(''currentShareToken'', v_token);
  END IF;

  IF v_share_light_id IS NOT NULL THEN
    v_content := v_content || jsonb_build_object(''share_light_id'', v_share_light_id);
    v_state := v_state || jsonb_build_object(''currentShareLightId'', v_share_light_id);
  END IF;

  v_state := v_state || jsonb_build_object(''contentSource'', ''share_light'');
  v_node := public.lumi_get_node(''SHARE_LIGHT_EDITOR'');

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''SHARE_LIGHT_EDITOR'',
    ''content_type'', ''share_light_editor'',
    ''content'', v_content,
    ''state'', v_state
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('392', 'CREATE OR REPLACE FUNCTION public.lumi_share_light__core(p_params jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_user_id             uuid;
  v_session_id          uuid;
  v_sanctuary_item_id   uuid;
  v_resource_id         uuid;
  v_experience_run_id   uuid;
  v_experience_id       uuid;
  v_surface_text        text;
  v_surface             public.share_light_surface;
  v_title               text;
  v_description_short   text;
  v_url                 text;
  v_default_text        text;
  v_resource            record;
  v_item                record;
  v_share               record;
  v_lumi_message        text;
  v_editor_title        text;
  v_editor_subtitle     text;
  v_editor_helper       text;
  v_privacy_hint        text;
  v_node                jsonb;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_user_id := NULLIF(TRIM(COALESCE(p_params->>''user_id'', p_params->>''currentUserId'', '''')), '''')::uuid;
  v_session_id := NULLIF(TRIM(COALESCE(p_params->>''session_id'', p_params->>''currentSessionId'', '''')), '''')::uuid;
  v_sanctuary_item_id := NULLIF(TRIM(COALESCE(p_params->>''sanctuary_item_id'', p_params->>''currentSanctuaryItemId'', '''')), '''')::uuid;
  v_resource_id := NULLIF(TRIM(COALESCE(p_params->>''resource_id'', p_params->>''currentResourceId'', '''')), '''')::uuid;
  v_experience_run_id := NULLIF(TRIM(COALESCE(p_params->>''experience_run_id'', p_params->>''currentExperienceRunId'', '''')), '''')::uuid;
  v_experience_id := NULLIF(TRIM(COALESCE(p_params->>''experience_id'', p_params->>''currentExperienceId'', '''')), '''')::uuid;

  v_surface_text := COALESCE(
    NULLIF(TRIM(p_params->>''surface''), ''''),
    NULLIF(TRIM(p_params->>''source''), ''''),
    NULLIF(TRIM(p_params->>''contentSource''), ''''),
    ''unknown''
  );

  v_surface := CASE
    WHEN v_surface_text IN (''sanctuary_saved'', ''sanctuary_detail'', ''experience_close'', ''resource_detail'', ''fallback'')
      THEN v_surface_text::public.share_light_surface
    WHEN v_surface_text = ''sanctuary''
      THEN ''sanctuary_detail''::public.share_light_surface
    ELSE ''unknown''::public.share_light_surface
  END;

  IF v_user_id IS NULL THEN
    v_node := public.lumi_get_node(''SHARE_LIGHT_REQUIRES_USER'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARE_LIGHT_REQUIRES_USER'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  IF v_sanctuary_item_id IS NOT NULL THEN
    SELECT
      si.id,
      COALESCE(si.resource_id, er.resource_id, e.primary_resource_id) AS resource_id,
      COALESCE(si.experience_id, er.experience_id) AS experience_id,
      si.experience_run_id,
      COALESCE(e.title, r.title, '''') AS title,
      COALESCE(r.description_short, e.objective, '''') AS description_short,
      COALESCE(r.url, r.reference_url, '''') AS url
    INTO v_item
    FROM public.sanctuary_items si
    LEFT JOIN public.experience_runs er ON er.id = si.experience_run_id
    LEFT JOIN public.experiences e ON e.id = COALESCE(si.experience_id, er.experience_id)
    LEFT JOIN public.resources r ON r.id = COALESCE(si.resource_id, er.resource_id, e.primary_resource_id)
    WHERE si.id = v_sanctuary_item_id
      AND si.user_id = v_user_id
    LIMIT 1;

    IF FOUND THEN
      v_resource_id := COALESCE(v_resource_id, v_item.resource_id);
      v_experience_id := COALESCE(v_experience_id, v_item.experience_id);
      v_experience_run_id := COALESCE(v_experience_run_id, v_item.experience_run_id);
      v_title := NULLIF(TRIM(COALESCE(v_item.title, '''')), '''');
      v_description_short := NULLIF(TRIM(COALESCE(v_item.description_short, '''')), '''');
      v_url := NULLIF(TRIM(COALESCE(v_item.url, '''')), '''');
    END IF;
  END IF;

  IF (v_title IS NULL OR v_description_short IS NULL OR v_url IS NULL)
     AND v_resource_id IS NOT NULL THEN
    SELECT r.id, r.title, r.description_short, COALESCE(r.url, r.reference_url, '''') AS url
    INTO v_resource
    FROM public.resources r
    WHERE r.id = v_resource_id
    LIMIT 1;

    IF FOUND THEN
      v_title := COALESCE(v_title, NULLIF(TRIM(COALESCE(v_resource.title, '''')), ''''));
      v_description_short := COALESCE(v_description_short, NULLIF(TRIM(COALESCE(v_resource.description_short, '''')), ''''));
      v_url := COALESCE(v_url, NULLIF(TRIM(COALESCE(v_resource.url, '''')), ''''));
    END IF;
  END IF;

  v_title := COALESCE(v_title, NULLIF(TRIM(COALESCE(p_params->>''title'', '''')), ''''), ''una experiencia de LUMEN'');
  v_description_short := COALESCE(v_description_short, NULLIF(TRIM(COALESCE(p_params->>''description_short'', p_params->>''description'', '''')), ''''));
  v_url := COALESCE(v_url, NULLIF(TRIM(COALESCE(p_params->>''url'', p_params->>''resource_url'', '''')), ''''));

  v_default_text := public.lumi_build_share_light_text(v_title, v_description_short, v_url);

  INSERT INTO public.share_light_circulations (
    created_by_user_id, session_id, source_surface, status, sanctuary_item_id,
    experience_run_id, experience_id, resource_id, title, description_short, url,
    default_text, editable_text, public_payload, metadata
  )
  VALUES (
    v_user_id, v_session_id, v_surface, ''prepared'', v_sanctuary_item_id,
    v_experience_run_id, v_experience_id, v_resource_id, v_title, v_description_short, v_url,
    v_default_text, v_default_text,
    jsonb_strip_nulls(jsonb_build_object(''title'', v_title, ''description_short'', v_description_short, ''url'', v_url)),
    jsonb_build_object(''src'', ''lumi_share_light'', ''surface'', v_surface::text)
  )
  RETURNING * INTO v_share;

  INSERT INTO public.share_light_events (
    share_light_id, user_id, session_id, event_type, channel, surface, success, metadata
  )
  VALUES (
    v_share.id, v_user_id, v_session_id, ''prepared'', ''unknown'', v_surface, true,
    jsonb_build_object(''text_length'', length(v_default_text), ''contains_url'', COALESCE(v_url, '''') <> '''')
  );

  IF v_session_id IS NOT NULL THEN
    INSERT INTO public.session_events (
      session_id, user_id, action_type, resource_id, experience_id, experience_run_id, metadata
    )
    VALUES (
      v_session_id, v_user_id, ''opened'', v_resource_id, v_experience_id, v_experience_run_id,
      jsonb_build_object(''event'', ''share_light_prepared'', ''share_light_id'', v_share.id, ''surface'', v_surface::text)
    );
  END IF;

  SELECT short_label, subtitle, helper_text
  INTO v_editor_title, v_editor_subtitle, v_editor_helper
  FROM public.ui_copy
  WHERE domain = ''share_light'' AND key = ''editor_title'' AND lang = ''es''
  LIMIT 1;

  SELECT short_label INTO v_privacy_hint
  FROM public.ui_copy
  WHERE domain = ''share_light'' AND key = ''privacy_hint'' AND lang = ''es''
  LIMIT 1;

  SELECT short_label INTO v_lumi_message
  FROM public.ui_copy
  WHERE domain = ''share_light'' AND key = ''lumi_ready_message'' AND lang = ''es''
  LIMIT 1;

  v_node := public.lumi_get_node(''SHARE_LIGHT_EDITOR'');

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''SHARE_LIGHT_EDITOR'',
    ''content_type'', ''share_light_editor'',
    ''content'', jsonb_build_object(
      ''type'', ''share_light_editor'',
      ''share_light_id'', v_share.id,
      ''share_token'', v_share.share_token,
      ''title'', v_title,
      ''description_short'', COALESCE(v_description_short, ''''),
      ''url'', COALESCE(v_url, ''''),
      ''default_text'', v_default_text,
      ''editable_text'', v_default_text,
      ''share_text'', v_default_text,
      ''editor_title'', COALESCE(v_editor_title, ''Compartir luz''),
      ''editor_subtitle'', COALESCE(v_editor_subtitle, ''Podés ajustar el texto antes de copiarlo o enviarlo.''),
      ''editor_helper'', COALESCE(v_editor_helper, ''Tu Santuario sigue siendo privado.''),
      ''privacy_hint'', COALESCE(v_privacy_hint, ''Tu Santuario sigue siendo privado.''),
      ''source'', ''share_light''
    ),
    ''state'', jsonb_build_object(
      ''contentSource'', ''share_light'',
      ''currentShareLightId'', v_share.id,
      ''currentResourceId'', COALESCE(v_resource_id::text, ''''),
      ''currentSanctuaryItemId'', COALESCE(v_sanctuary_item_id::text, ''''),
      ''currentExperienceRunId'', COALESCE(v_experience_run_id::text, '''')
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('394', 'CREATE OR REPLACE FUNCTION public.lumi_skip_name(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  RETURN public.lumi_submit_name(p_params || jsonb_build_object(''first_name'', ''''));
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('396', 'CREATE OR REPLACE FUNCTION public.lumi_start_checkin(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id         uuid;
  v_session_id      uuid;
  v_node            jsonb;
  v_context         jsonb;
  v_message         text;
  v_culture_phrase  text;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));
  v_user_id := nullif(trim(p_params->>''user_id''), '''')::uuid;

  IF v_user_id IS NULL THEN
    RETURN public.lumi_get_node(''HOME_DEFAULT'')
      || jsonb_build_object(
        ''ok'', false,
        ''error'', ''user_id requerido'',
        ''state'', public.lumi_clear_conversation_state('''', ''#7860E0'', '''', '''')
      );
  END IF;

  INSERT INTO public.sessions (user_id)
  VALUES (v_user_id)
  RETURNING id INTO v_session_id;

  v_context := public.lumi_get_presence_context(v_user_id);
  v_node    := public.lumi_get_node(''LUMI_PRESENCE_ENTRY'');

  v_culture_phrase := COALESCE(public.lumi_get_message(''culture_phrase'', ''first_contact''), '''');

  v_message := CASE
    WHEN NOT COALESCE((v_context->>''has_history'')::boolean, false) THEN
      COALESCE(
        v_node->>''message'',
        ''Tomemos un instante para llegar. ¿Querés mirar algo que está pasando ahora o avanzar en algo de tu vida?''
      )
    WHEN COALESCE((v_context->>''days_since_last_session'')::integer, 0) >= 7 THEN
      ''Qué bueno verte de vuelta. ¿Cómo llegás hoy?''
    WHEN COALESCE((v_context->>''days_since_last_session'')::integer, 0) >= 1 THEN
      ''¿Cómo llegás hoy?''
    ELSE
      ''¿Cómo llegás ahora?''
  END;

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         ''LUMI_PRESENCE_ENTRY'',
    ''message'',      v_message,
    ''actions'',      COALESCE(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', ''empty_presence'',
    ''content'',      jsonb_build_object(
                      ''type'',           ''empty_presence'',
                      ''context'',        v_context,
                      ''culture_phrase'', v_culture_phrase
                    ),
    ''state'',        public.lumi_clear_conversation_state(
                      ''lumi'',
                      ''#7860E0'',
                      v_session_id::text,
                      ''''
                    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('397', 'CREATE OR REPLACE FUNCTION public.lumi_start_experience(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_user_id       uuid;
  v_session_id    uuid;
  v_result        jsonb;
  v_node          jsonb;
  v_hemisphere    text;
  v_area          text;
  v_state_key     text;
  v_faro_key      text;
  v_capability    text;
  v_time_bucket   text;
BEGIN
  p_params     := public.lumi_normalize_params(p_params);
  v_user_id    := NULLIF(TRIM(p_params->>''user_id''), '''')::uuid;
  v_session_id := NULLIF(TRIM(p_params->>''session_id''), '''')::uuid;

  IF v_user_id IS NULL THEN
    RETURN public.lumi_get_node(''HOME_DEFAULT'') || jsonb_build_object(''ok'', false, ''error'', ''user_id requerido'', ''state'', ''{}''::jsonb);
  END IF;

  v_result := public.lumi_select_experience(p_user_id := v_user_id, p_session_id := v_session_id);

  IF v_session_id IS NOT NULL THEN
    SELECT s.hemisphere_key, s.area::text, s.state_key, s.faro_key, s.selected_capability_key, s.time_bucket::text
    INTO v_hemisphere, v_area, v_state_key, v_faro_key, v_capability, v_time_bucket
    FROM public.sessions s
    WHERE s.id = v_session_id AND s.user_id = v_user_id;
  END IF;

  IF NOT COALESCE((v_result->>''matched'')::boolean, false) THEN
    IF (v_result->>''fallback_reason'') = ''time_mismatch'' THEN
      v_node := public.lumi_get_node(''TIME_MISMATCH_OFFER'');
      RETURN v_node || jsonb_build_object(
        ''ok'', true,
        ''code'', ''TIME_MISMATCH_OFFER'',
        ''message'', COALESCE(NULLIF(v_result->>''negotiation_msg'', ''''), v_node->>''message''),
        ''content_type'', ''empty_presence'',
        ''content'', jsonb_build_object(''type'', ''empty_presence'') || v_result,
        ''state'', jsonb_build_object(
          ''currentSessionId'', COALESCE(v_session_id::text, ''''),
          ''checkinHemisphere'', COALESCE(v_hemisphere, ''''),
          ''checkinArea'', COALESCE(v_area, ''''),
          ''checkinState'', COALESCE(v_state_key, ''''),
          ''checkinFaro'', COALESCE(v_faro_key, ''''),
          ''checkinCapability'', COALESCE(v_capability, ''''),
          ''checkinTime'', COALESCE(v_time_bucket, '''')
        )
      );
    END IF;

    IF (v_result->>''fallback_reason'') = ''format_mismatch'' THEN
      v_node := public.lumi_get_node(''FORMAT_MISMATCH_OFFER'');
      RETURN v_node || jsonb_build_object(
        ''ok'', true,
        ''code'', ''FORMAT_MISMATCH_OFFER'',
        ''message'', COALESCE(NULLIF(v_result->>''negotiation_msg'', ''''), v_node->>''message''),
        ''content_type'', ''empty_presence'',
        ''content'', jsonb_build_object(''type'', ''empty_presence'') || v_result,
        ''state'', jsonb_build_object(
          ''currentSessionId'', COALESCE(v_session_id::text, ''''),
          ''checkinHemisphere'', COALESCE(v_hemisphere, ''''),
          ''checkinArea'', COALESCE(v_area, ''''),
          ''checkinState'', COALESCE(v_state_key, ''''),
          ''checkinFaro'', COALESCE(v_faro_key, ''''),
          ''checkinCapability'', COALESCE(v_capability, ''''),
          ''checkinTime'', COALESCE(v_time_bucket, '''')
        )
      );
    END IF;

    v_node := public.lumi_get_node(''NO_MATCH_HONEST'');
    RETURN v_node || jsonb_build_object(
      ''ok'', true,
      ''code'', ''NO_MATCH_HONEST'',
      ''content_type'', ''empty_presence'',
      ''content'', jsonb_build_object(''type'', ''empty_presence''),
      ''state'', jsonb_build_object(
        ''currentSessionId'', COALESCE(v_session_id::text, ''''),
        ''checkinHemisphere'', COALESCE(v_hemisphere, ''''),
        ''checkinArea'', COALESCE(v_area, ''''),
        ''checkinState'', COALESCE(v_state_key, ''''),
        ''checkinFaro'', COALESCE(v_faro_key, ''''),
        ''checkinCapability'', COALESCE(v_capability, ''''),
        ''checkinTime'', COALESCE(v_time_bucket, '''')
      )
    );
  END IF;

  v_node := public.lumi_get_node(''EXPERIENCE_PRE'');
  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''EXPERIENCE_PRE'',
    ''message'', COALESCE(NULLIF(v_result->>''pre_text'', ''''), v_node->>''message''),
    ''content_type'', ''empty_presence'',
    ''content'', jsonb_build_object(
      ''type'', ''empty_presence'',
      ''experience_id'', v_result->>''experience_id'',
      ''experience_code'', v_result->>''experience_code'',
      ''run_id'', v_result->>''run_id'',
      ''capability_key'', v_result->>''capability_key'',
      ''expected_capability_key'', v_result->>''expected_capability'',
      ''resource_id'', v_result->''resource''->>''id'',
      ''resource_title'', v_result->''resource''->>''title'',
      ''resource_format'', v_result->''resource''->>''format'',
      ''resource_url'', v_result->''resource''->>''url'',
      ''post_text'', v_result->>''post_text''
    ),
    ''state'', jsonb_build_object(
      ''currentSessionId'', COALESCE(v_session_id::text, ''''),
      ''currentResourceId'', v_result->''resource''->>''id'',
      ''currentExperienceRunId'', v_result->>''run_id'',
      ''checkinHemisphere'', COALESCE(v_hemisphere, ''''),
      ''checkinArea'', COALESCE(v_area, ''''),
      ''checkinState'', COALESCE(v_state_key, ''''),
      ''checkinFaro'', COALESCE(v_faro_key, ''''),
      ''checkinCapability'', COALESCE(v_capability, ''''),
      ''checkinTime'', COALESCE(v_time_bucket, ''''),
      ''contentSource'', ''lumi''
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('399', 'CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_area(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE v_user_id uuid; v_session_id uuid; v_area text; v_hemi text; v_node jsonb; v_options jsonb;
BEGIN
  p_params:=public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb));
  v_user_id:=NULLIF(trim(p_params->>''user_id''),'''')::uuid;
  v_session_id:=NULLIF(trim(p_params->>''session_id''),'''')::uuid;
  v_area:=NULLIF(trim(COALESCE(NULLIF(p_params->>''value'',''''),p_params->>''checkin_area'')),'''');
  v_hemi:=COALESCE(NULLIF(trim(p_params->>''checkin_hemisphere''),''''),''H2'');
  IF v_hemi<>''H2'' OR v_area IS NULL THEN RETURN public.lumi_submit_checkin_hemisphere(p_params); END IF;
  UPDATE public.sessions SET area=v_area::public.life_area,faro_key=NULL,user_area_faro_id=NULL,selected_capability_key=NULL,time_bucket=NULL
   WHERE id=v_session_id AND user_id=v_user_id;
  v_options:=public.lumi_checkin_options(''faro'',v_user_id,''H2'',v_area);
  IF jsonb_array_length(v_options)=0 THEN RETURN public.lumi_checkin_no_match(''faro'',''H2'',jsonb_build_object(''currentSessionId'',COALESCE(v_session_id::text,''''),''checkinHemisphere'',''H2'',''checkinArea'',v_area,''contentSource'',''lumi'')); END IF;
  v_node:=public.lumi_get_node(''CHECKIN_FARO_H2'');
  RETURN v_node||jsonb_build_object(''ok'',true,''content_type'',''checkin_options'',''content'',jsonb_build_object(''type'',''checkin_options'',''step'',''faro'',''options'',v_options),
    ''state'',jsonb_build_object(''currentSessionId'',COALESCE(v_session_id::text,''''),''checkinHemisphere'',''H2'',''checkinArea'',v_area,''contentSource'',''lumi''));
END; $function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('400', 'CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_capability(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE v_user_id uuid; v_session_id uuid; v_cap text; v_hemi text; v_area text; v_state text; v_faro text; v_node jsonb; v_options jsonb;
BEGIN
  p_params:=public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb));
  v_user_id:=NULLIF(trim(p_params->>''user_id''),'''')::uuid; v_session_id:=NULLIF(trim(p_params->>''session_id''),'''')::uuid;
  v_cap:=NULLIF(trim(COALESCE(NULLIF(p_params->>''value'',''''),p_params->>''checkin_capability'')),'''');
  v_hemi:=COALESCE(NULLIF(trim(p_params->>''checkin_hemisphere''),''''),''H1''); v_area:=NULLIF(trim(p_params->>''checkin_area''),'''');
  v_state:=NULLIF(trim(p_params->>''checkin_state''),''''); v_faro:=NULLIF(trim(p_params->>''checkin_faro''),'''');
  IF v_cap IS NULL OR NOT EXISTS(SELECT 1 FROM public.lumi_checkin_candidates(v_hemi,v_area,v_state,v_faro,v_cap,NULL)) THEN
    IF v_hemi=''H2'' THEN RETURN public.lumi_submit_checkin_faro(p_params); ELSE RETURN public.lumi_submit_checkin_state(p_params); END IF;
  END IF;
  UPDATE public.sessions SET selected_capability_key=v_cap,time_bucket=NULL WHERE id=v_session_id AND user_id=v_user_id;
  v_options:=public.lumi_checkin_options(''time'',v_user_id,v_hemi,v_area,v_state,v_faro,v_cap);
  IF jsonb_array_length(v_options)=0 THEN RETURN public.lumi_checkin_no_match(''time'',v_hemi,jsonb_build_object(''currentSessionId'',COALESCE(v_session_id::text,''''),''checkinHemisphere'',v_hemi,''checkinArea'',COALESCE(v_area,''''),''checkinState'',COALESCE(v_state,''''),''checkinFaro'',COALESCE(v_faro,''''),''checkinCapability'',v_cap,''contentSource'',''lumi'')); END IF;
  v_node:=public.lumi_get_node(''CHECKIN_TIME'');
  RETURN v_node||jsonb_build_object(''ok'',true,''content_type'',''checkin_options'',''content'',jsonb_build_object(''type'',''checkin_options'',''step'',''time'',''options'',v_options),
    ''state'',jsonb_build_object(''currentSessionId'',COALESCE(v_session_id::text,''''),''checkinHemisphere'',v_hemi,''checkinArea'',COALESCE(v_area,''''),''checkinState'',COALESCE(v_state,''''),''checkinFaro'',COALESCE(v_faro,''''),''checkinCapability'',v_cap,''contentSource'',''lumi''));
END; $function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('401', 'CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_faro(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE v_user_id uuid; v_session_id uuid; v_uaf_id uuid; v_area text; v_faro text; v_label text; v_node jsonb; v_options jsonb;
BEGIN
  p_params:=public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb));
  v_user_id:=NULLIF(trim(p_params->>''user_id''),'''')::uuid; v_session_id:=NULLIF(trim(p_params->>''session_id''),'''')::uuid;
  v_uaf_id:=NULLIF(trim(COALESCE(NULLIF(p_params->>''value'',''''),p_params->>''user_area_faro_id'',p_params->>''resource_id'')),'''')::uuid;
  SELECT uaf.area::text,uaf.faro_key,COALESCE(uc.short_label,uaf.faro_text,uaf.faro_key)
   INTO v_area,v_faro,v_label FROM public.user_area_faros uaf LEFT JOIN public.ui_copy uc ON uc.domain=''faro'' AND uc.lang=''es'' AND uc.key=uaf.faro_key
   WHERE uaf.id=v_uaf_id AND uaf.user_id=v_user_id AND uaf.status=''active'';
  IF v_faro IS NULL THEN RETURN public.lumi_submit_checkin_area(p_params); END IF;
  UPDATE public.sessions SET area=v_area::public.life_area,faro_key=v_faro,user_area_faro_id=v_uaf_id,selected_capability_key=NULL,time_bucket=NULL
   WHERE id=v_session_id AND user_id=v_user_id;
  v_options:=public.lumi_checkin_options(''capability'',v_user_id,''H2'',v_area,NULL,v_faro,NULL);
  IF jsonb_array_length(v_options)=0 THEN RETURN public.lumi_checkin_no_match(''capability'',''H2'',jsonb_build_object(''currentSessionId'',COALESCE(v_session_id::text,''''),''checkinHemisphere'',''H2'',''checkinArea'',v_area,''checkinFaro'',v_faro,''contentSource'',''lumi'')); END IF;
  v_node:=public.lumi_get_node(''CHECKIN_CAPABILITY_H2'');
  RETURN v_node||jsonb_build_object(''ok'',true,''message'',''¿Qué te ayudaría a avanzar hacia "''||v_label||''"?'',
    ''content_type'',''checkin_options'',''content'',jsonb_build_object(''type'',''checkin_options'',''step'',''capability'',''options'',v_options),
    ''state'',jsonb_build_object(''currentSessionId'',COALESCE(v_session_id::text,''''),''checkinHemisphere'',''H2'',''checkinArea'',v_area,''checkinFaro'',v_faro,''contentSource'',''lumi''));
END; $function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('402', 'CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_hemisphere(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_user_id uuid;
  v_session_id uuid;
  v_hemisphere text;
  v_node jsonb;
  v_options jsonb;
  v_scan record;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb));
  v_user_id := NULLIF(trim(p_params->>''user_id''),'''')::uuid;
  v_session_id := NULLIF(trim(p_params->>''session_id''),'''')::uuid;
  v_hemisphere := NULLIF(trim(COALESCE(NULLIF(p_params->>''value'',''''),p_params->>''checkin_hemisphere'')),'''');

  IF v_hemisphere NOT IN (''H1'',''H2'') THEN RETURN public.lumi_start_checkin(p_params); END IF;
  IF v_user_id IS NULL THEN RETURN public.lumi_get_node(''HOME_DEFAULT'') || jsonb_build_object(''ok'',false,''error'',''user_id requerido''); END IF;

  IF v_session_id IS NULL THEN
    INSERT INTO public.sessions(user_id,hemisphere_key) VALUES(v_user_id,v_hemisphere) RETURNING id INTO v_session_id;
  ELSE
    UPDATE public.sessions SET hemisphere_key=v_hemisphere, area=NULL, state_key=NULL,
      faro_key=NULL, user_area_faro_id=NULL, selected_capability_key=NULL, time_bucket=NULL
    WHERE id=v_session_id AND user_id=v_user_id;
  END IF;

  IF v_hemisphere=''H1'' THEN
    SELECT code,message_text,actions_json,content_json INTO v_scan
    FROM public.lumen_nodes WHERE moment_type=''landing_scan'' AND active ORDER BY random() LIMIT 1;
    IF FOUND THEN
      RETURN jsonb_build_object(''ok'',true,''code'',v_scan.code,''message'',COALESCE(v_scan.message_text,''''),
        ''actions'',COALESCE(v_scan.actions_json,''[]''::jsonb),''content_type'',''activity_detail'',
        ''content'',COALESCE(v_scan.content_json,''{}''::jsonb)||jsonb_build_object(''type'',''activity_detail'',''detail_kind'',''landing_scan'',''source'',''home''),
        ''state'',jsonb_build_object(''currentSessionId'',v_session_id::text,''checkinHemisphere'',''H1'',''contentSource'',''lumi''));
    END IF;
    RETURN public.lumi_complete_scan(p_params||jsonb_build_object(''session_id'',v_session_id::text));
  END IF;

  v_options := public.lumi_checkin_options(''area'',v_user_id,''H2'');
  IF jsonb_array_length(v_options)=0 THEN
    v_node := public.lumi_get_node(''H2_NO_ACTIVE_FAROS'');
    RETURN v_node || jsonb_build_object(''ok'',true,''code'',''H2_NO_ACTIVE_FAROS'',
      ''message'',''Para acompañarte con continuidad, primero elijamos uno o más Faros para este tramo de tu vida.'',
      ''actions'',jsonb_build_array(
        jsonb_build_object(''label'',''Elegir mis Faros'',''action'',''open_faros'',''variant'',''solid''),
        jsonb_build_object(''label'',''Volver'',''action'',''go_home'',''variant'',''ghost'')),
      ''content_type'',''empty_presence'',''content'',jsonb_build_object(''type'',''empty_presence'',''source'',''lumi''),
      ''state'',jsonb_build_object(''currentSessionId'',v_session_id::text,''checkinHemisphere'',''H2'',''contentSource'',''lumi''));
  END IF;

  v_node := public.lumi_get_node(''CHECKIN_AREA'');
  RETURN v_node || jsonb_build_object(''ok'',true,''code'',''CHECKIN_AREA'',
    ''message'',''¿En qué parte de tu territorio querés avanzar?'',
    ''content_type'',''checkin_options'',''content'',jsonb_build_object(''type'',''checkin_options'',''step'',''area'',''options'',v_options),
    ''state'',jsonb_build_object(''currentSessionId'',v_session_id::text,''checkinHemisphere'',''H2'',''contentSource'',''lumi''));
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('403', 'CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_state(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE v_user_id uuid; v_session_id uuid; v_state text; v_node jsonb; v_options jsonb;
BEGIN
  p_params:=public.lumi_normalize_params(COALESCE(p_params,''{}''::jsonb));
  v_user_id:=NULLIF(trim(p_params->>''user_id''),'''')::uuid; v_session_id:=NULLIF(trim(p_params->>''session_id''),'''')::uuid;
  v_state:=NULLIF(trim(COALESCE(NULLIF(p_params->>''value'',''''),p_params->>''checkin_state'')),'''');
  IF v_state IS NULL THEN RETURN public.lumi_complete_scan(p_params); END IF;
  UPDATE public.sessions SET state_key=v_state,selected_capability_key=NULL,time_bucket=NULL WHERE id=v_session_id AND user_id=v_user_id;
  v_options:=public.lumi_checkin_options(''capability'',v_user_id,''H1'',NULL,v_state,NULL,NULL);
  IF jsonb_array_length(v_options)=0 THEN RETURN public.lumi_checkin_no_match(''capability'',''H1'',jsonb_build_object(''currentSessionId'',COALESCE(v_session_id::text,''''),''checkinHemisphere'',''H1'',''checkinState'',v_state,''contentSource'',''lumi'')); END IF;
  v_node:=public.lumi_get_node(''CHECKIN_CAPABILITY_H1'');
  RETURN v_node||jsonb_build_object(''ok'',true,''content_type'',''checkin_options'',''content'',jsonb_build_object(''type'',''checkin_options'',''step'',''capability'',''options'',v_options),
    ''state'',jsonb_build_object(''currentSessionId'',COALESCE(v_session_id::text,''''),''checkinHemisphere'',''H1'',''checkinArea'','''',''checkinState'',v_state,''checkinFaro'','''',''contentSource'',''lumi''));
END; $function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('404', 'CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_time(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$DECLARE
  v_user_id    uuid;
  v_session_id uuid;
  v_time       text;
  v_format     text;
BEGIN
  p_params     := public.lumi_normalize_params(p_params);
  v_user_id    := nullif(trim(p_params->>''user_id''), '''')::uuid;
  v_session_id := nullif(trim(p_params->>''session_id''), '''')::uuid;
  v_time := nullif(trim(coalesce(nullif(p_params->>''value'',''''), p_params->>''checkin_time'')), '''');
  v_format     := nullif(trim(p_params->>''checkin_format''), '''');

  -- Sin tiempo → volver a mostrarlo
  IF v_time IS NULL THEN
    RETURN public.lumi_submit_checkin_capability(p_params);
  END IF;

  -- Guardar disponibilidad en sesión
  IF v_session_id IS NOT NULL THEN
    UPDATE public.sessions
    SET time_bucket              = v_time::public.time_bucket,
        current_format_preference = v_format,
        landing_completed        = true
    WHERE id = v_session_id AND user_id = v_user_id;
  END IF;

  -- Lanzar el motor canónico
  RETURN public.lumi_start_experience(
    p_params || jsonb_build_object(''checkin_time'', v_time)
  );
END;$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('405', 'CREATE OR REPLACE FUNCTION public.lumi_submit_feedback_effect(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_run_id uuid;
  v_raw_value text;
  v_candidate_capability text;
  v_perceived text;
  v_run record;
  v_convergence boolean;
  v_source text;
  v_sanctuary_item_id uuid;
  v_is_sanctuary_replay boolean := false;
  v_node jsonb;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_run_id := NULLIF(trim(COALESCE(p_params->>''experience_run_id'', p_params->>''currentExperienceRunId'')), '''')::uuid;
  v_raw_value := NULLIF(trim(COALESCE(p_params->>''value'', p_params->>''feedback_effect'', p_params->>''effect'', '''')), '''');
  v_candidate_capability := NULLIF(trim(COALESCE(p_params->>''perceived_capability_key'', p_params->>''checkin_capability'', p_params->>''selected_capability_key'', '''')), '''');

  IF v_run_id IS NULL THEN
    v_node := public.lumi_get_node(''FEEDBACK_EFFECT_ERROR'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''FEEDBACK_EFFECT_ERROR'',
      ''error'', ''experience_run_id requerido'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  SELECT er.id, er.user_id, er.experience_id, er.resource_id, er.expected_capability_key,
         er.perceived_capability_key, er.selected_capability_key, er.primary_capability_key,
         er.experience_hypothesis_id, er.hypothesis_json, er.metadata
  INTO v_run
  FROM public.experience_runs er
  WHERE er.id = v_run_id;

  IF v_run IS NULL THEN
    v_node := public.lumi_get_node(''FEEDBACK_EFFECT_ERROR'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''FEEDBACK_EFFECT_ERROR'',
      ''error'', ''run no encontrado'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  v_source := COALESCE(v_run.hypothesis_json->>''source'', p_params->>''source'', p_params->>''contentSource'', '''');

  v_sanctuary_item_id := NULLIF(trim(COALESCE(
    p_params->>''sanctuary_item_id'',
    p_params->>''currentSanctuaryItemId'',
    v_run.hypothesis_json->>''sanctuary_item_id'',
    ''''
  )), '''')::uuid;

  IF v_sanctuary_item_id IS NULL THEN
    SELECT si.id
    INTO v_sanctuary_item_id
    FROM public.sanctuary_items si
    WHERE si.user_id = v_run.user_id
      AND si.experience_id = v_run.experience_id
      AND si.experience_run_id IS NOT NULL
      AND si.created_at < now()
    ORDER BY si.created_at DESC
    LIMIT 1;
  END IF;

  v_is_sanctuary_replay := (v_source = ''sanctuary_replay'' OR v_source = ''sanctuary'' OR v_sanctuary_item_id IS NOT NULL);

  IF v_candidate_capability IS NOT NULL
     AND EXISTS (SELECT 1 FROM public.ui_copy uc WHERE uc.domain = ''capability'' AND uc.lang = ''es'' AND uc.key = v_candidate_capability)
  THEN
    v_perceived := v_candidate_capability;
  ELSE
    v_perceived := NULL;
  END IF;

  UPDATE public.experience_runs
  SET perceived_capability_key = COALESCE(v_perceived, perceived_capability_key),
      reflection_text = COALESCE(reflection_text, v_raw_value),
      metadata = COALESCE(metadata, ''{}''::jsonb) || jsonb_build_object(
        ''feedback_effect_value'', v_raw_value,
        ''feedback_effect_recorded_at'', now(),
        ''feedback_source_detected'', v_source,
        ''sanctuary_replay_detected'', v_is_sanctuary_replay
      )
  WHERE id = v_run_id;

  v_convergence := (v_perceived IS NOT NULL AND v_run.expected_capability_key IS NOT NULL AND v_run.expected_capability_key = v_perceived);

  IF v_is_sanctuary_replay THEN
    v_node := public.lumi_get_node(''POST_REPLAY_SHARE_OFFER'');
    RETURN v_node || jsonb_build_object(
      ''ok'', true,
      ''code'', ''POST_REPLAY_SHARE_OFFER'',
      ''convergence'', v_convergence,
      ''content_type'', ''empty_presence'',
      ''content'', jsonb_build_object(
        ''type'', ''empty_presence'',
        ''source'', ''sanctuary'',
        ''detail_kind'', ''sanctuary'',
        ''sanctuary_item_id'', COALESCE(v_sanctuary_item_id::text, '''')
      ),
      ''state'', jsonb_build_object(
        ''currentExperienceRunId'', v_run_id::text,
        ''currentSanctuaryItemId'', COALESCE(v_sanctuary_item_id::text, ''''),
        ''currentResourceId'', COALESCE(v_run.resource_id::text, ''''),
        ''contentSource'', ''sanctuary''
      )
    );
  END IF;

  v_node := public.lumi_get_node(''POST_EFFECT_OFFER'');
  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''POST_EFFECT_OFFER'',
    ''convergence'', v_convergence,
    ''content_type'', ''empty_presence'',
    ''content'', jsonb_build_object(''type'', ''empty_presence'', ''source'', COALESCE(p_params->>''source'', ''lumi'')),
    ''state'', jsonb_build_object(
      ''currentExperienceRunId'', v_run_id::text,
      ''currentResourceId'', COALESCE(v_run.resource_id::text, ''''),
      ''contentSource'', COALESCE(p_params->>''source'', ''lumi'')
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('406', 'CREATE OR REPLACE FUNCTION public.lumi_submit_h2_choose_area(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_node    jsonb;
  v_options jsonb;
BEGIN
  v_node := public.lumi_get_node(''CHECKIN_AREA'');

  SELECT jsonb_agg(
    jsonb_build_object(''value'', uc.key, ''label'', uc.short_label, ''hint'', uc.subtitle)
    ORDER BY uc.sort_order, uc.key
  ) INTO v_options
  FROM public.ui_copy uc
  WHERE uc.domain = ''area'' AND uc.lang = ''es'';

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         ''CHECKIN_AREA'',
    ''message'',      coalesce(v_node->>''message'',
                      ''¿En qué área de tu vida querés poner energía?''),
    ''actions'',      ''[]''::jsonb,
    ''content_type'', ''checkin_options'',
    ''content'',      jsonb_build_object(
                      ''type'',    ''checkin_options'',
                      ''step'',    ''area'',
                      ''options'', coalesce(v_options, ''[]''::jsonb)
                    ),
    ''state'',        ''{}''::jsonb
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('407', 'CREATE OR REPLACE FUNCTION public.lumi_submit_h2_resume_faro(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id uuid;
  v_session_id uuid;
  v_context jsonb;
  v_last_faro jsonb;
  v_area text;
  v_faro_key text;
  v_user_area_faro_id uuid;
  v_node jsonb;
  v_options jsonb;
BEGIN
  p_params := public.lumi_normalize_params(p_params);

  v_user_id := NULLIF(trim(p_params->>''user_id''), '''')::uuid;
  v_session_id := NULLIF(trim(p_params->>''session_id''), '''')::uuid;

  v_context := public.lumi_get_presence_context(v_user_id);
  v_last_faro := v_context->''last_faro_worked'';

  IF v_last_faro IS NULL THEN
    RETURN public.lumi_submit_h2_choose_area(p_params);
  END IF;

  v_area := v_last_faro->>''area'';
  v_faro_key := v_last_faro->>''faro_key'';
  v_user_area_faro_id := NULLIF(v_last_faro->>''user_area_faro_id'', '''')::uuid;

  IF v_session_id IS NOT NULL THEN
    UPDATE public.sessions
    SET
      area = v_area::public.life_area,
      faro_key = v_faro_key,
      user_area_faro_id = v_user_area_faro_id
    WHERE id = v_session_id
      AND user_id = v_user_id;
  END IF;

  v_node := public.lumi_get_node(''CHECKIN_CAPABILITY_H2'');

  SELECT jsonb_agg(
    jsonb_build_object(
      ''value'', uc.key,
      ''label'', uc.short_label,
      ''hint'', uc.subtitle
    )
    ORDER BY uc.sort_order NULLS LAST, uc.key
  )
  INTO v_options
  FROM public.ui_copy uc
  WHERE uc.domain = ''capability''
    AND uc.lang = ''es'';

  RETURN jsonb_build_object(
    ''ok'', true,
    ''code'', ''CHECKIN_CAPABILITY_H2'',
    ''message'', COALESCE(v_node->>''message'', ''¿Qué te ayudaría a avanzar en este momento?''),
    ''actions'', ''[]''::jsonb,
    ''content_type'', ''checkin_options'',
    ''content'', jsonb_build_object(
      ''type'', ''checkin_options'',
      ''step'', ''capability'',
      ''options'', COALESCE(v_options, ''[]''::jsonb)
    ),
    ''state'', jsonb_build_object(
      ''checkinArea'', v_area,
      ''checkinFaro'', v_faro_key
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('415', 'CREATE OR REPLACE FUNCTION realtime.broadcast_changes(topic_name text, event_name text, operation text, table_name text, table_schema text, new record, old record, level text DEFAULT ''ROW''::text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Declare a variable to hold the JSONB representation of the row
    row_data jsonb := ''{}''::jsonb;
BEGIN
    IF level = ''STATEMENT'' THEN
        RAISE EXCEPTION ''function can only be triggered for each row, not for each statement'';
    END IF;
    -- Check the operation type and handle accordingly
    IF operation = ''INSERT'' OR operation = ''UPDATE'' OR operation = ''DELETE'' THEN
        row_data := jsonb_build_object(''old_record'', OLD, ''record'', NEW, ''operation'', operation, ''table'', table_name, ''schema'', table_schema);
        PERFORM realtime.send (row_data, event_name, topic_name);
    ELSE
        RAISE EXCEPTION ''Unexpected operation type: %'', operation;
    END IF;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION ''Failed to process the row: %'', SQLERRM;
END;

$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('408', 'CREATE OR REPLACE FUNCTION public.lumi_submit_name(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id    uuid;
  v_first_name text;
  v_node       jsonb;
  v_message    text;
BEGIN
  v_user_id    := nullif(trim(p_params->>''user_id''), '''')::uuid;
  v_first_name := nullif(trim(p_params->>''first_name''), '''');

  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object(''ok'', false, ''error'', ''missing_user_id'');
  END IF;

  IF v_first_name IS NOT NULL AND length(v_first_name) > 0 THEN
    UPDATE public.users
    SET first_name = substring(v_first_name from 1 for 40), has_visited = true
    WHERE id = v_user_id;
    v_message := ''Hola, '' || substring(v_first_name from 1 for 40)
              || ''. No hace falta que sepas qué necesitás. Podemos empezar por algo pequeño.'';
  ELSE
    UPDATE public.users SET has_visited = true WHERE id = v_user_id;
    v_message := ''No hace falta que sepas qué necesitás. Podemos empezar por algo pequeño.'';
  END IF;

  v_node := public.lumi_get_node(''HOME_DEFAULT'');

  RETURN jsonb_build_object(
    ''ok'',           true,
    ''code'',         ''HOME_DEFAULT'',
    ''message'',      v_message,
    ''actions'',      coalesce(v_node->''actions'', ''[]''::jsonb),
    ''content_type'', ''empty_presence'',
    ''content'',      jsonb_build_object(''type'', ''empty_presence''),
    ''state'', jsonb_build_object(
      ''contentSource'', '''', ''moduleColor'', ''#7860E0'',
      ''currentSessionId'', '''', ''currentResourceId'', '''', ''currentSanctuaryItemId'', ''''
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('409', 'CREATE OR REPLACE FUNCTION public.lumi_submit_shared_light_signal(p_params jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_token             text;
  v_signal            text;
  v_user_id           uuid;
  v_auth_user_id      uuid;
  v_has_real_account  boolean := false;
  v_share             record;
  v_node              jsonb;
  v_run_id            uuid;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_user_id := NULLIF(TRIM(COALESCE(p_params->>''user_id'', '''')), '''')::uuid;
  v_auth_user_id := auth.uid();
  v_user_id := COALESCE(v_user_id, v_auth_user_id);

  SELECT EXISTS (
    SELECT 1
    FROM auth.users au
    WHERE au.id = v_user_id
      AND NULLIF(TRIM(au.email), '''') IS NOT NULL
  )
  INTO v_has_real_account;

  v_token := NULLIF(TRIM(COALESCE(
    p_params->>''share_token'',
    p_params->>''currentShareToken'',
    ''''
  )), '''');

  v_signal := COALESCE(
    NULLIF(TRIM(p_params->>''value''), ''''),
    NULLIF(TRIM(p_params->>''help_signal''), ''''),
    ''unknown''
  );

  v_run_id := NULLIF(TRIM(COALESCE(
    p_params->>''experience_run_id'',
    p_params->>''currentExperienceRunId'',
    ''''
  )), '''')::uuid;

  SELECT *
  INTO v_share
  FROM public.share_light_circulations
  WHERE share_token = v_token
    AND status NOT IN (''revoked'', ''expired'')
    AND (expires_at IS NULL OR expires_at > now())
  LIMIT 1;

  IF NOT FOUND THEN
    v_node := public.lumi_get_node(''SHARED_LIGHT_NOT_FOUND'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARED_LIGHT_NOT_FOUND'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  /*
    Fallback: si el frontend no mandó el run, buscar el último run receptor
    creado para esta luz y este usuario técnico.
  */
  IF v_run_id IS NULL AND v_user_id IS NOT NULL THEN
    SELECT er.id
    INTO v_run_id
    FROM public.experience_runs er
    WHERE er.user_id = v_user_id
      AND er.metadata->>''source_hint'' = ''shared_light_receiver''
      AND er.metadata->>''share_light_id'' = v_share.id::text
    ORDER BY er.started_at DESC NULLS LAST
    LIMIT 1;
  END IF;

  IF v_run_id IS NOT NULL THEN
    UPDATE public.experience_runs er
    SET
      help_signal = v_signal,
      canonical_help_signal = v_signal,
      completed_at = COALESCE(er.completed_at, now()),
      metadata = COALESCE(er.metadata, ''{}''::jsonb) || jsonb_build_object(
        ''shared_light_feedback_at'', now(),
        ''shared_light_help_signal'', v_signal,
        ''share_light_id'', v_share.id::text,
        ''share_token'', v_share.share_token
      )
    WHERE er.id = v_run_id;
  END IF;

  INSERT INTO public.share_light_events (
    share_light_id, user_id, session_id, event_type, channel, surface, success, metadata
  )
  VALUES (
    v_share.id,
    v_user_id,
    NULL,
    ''opened'',
    ''link'',
    ''unknown'',
    true,
    jsonb_build_object(
      ''anonymous'', NOT v_has_real_account,
      ''step'', ''anonymous_signal'',
      ''help_signal'', v_signal,
      ''receiver_experience_run_id'', COALESCE(v_run_id::text, '''')
    )
  );

  IF v_signal = ''me_dejo_un_poco_mejor''
     AND NOT v_has_real_account THEN
    v_node := public.lumi_get_node(''REGISTRATION_PROMPT'');

    RETURN v_node || jsonb_build_object(
      ''ok'', true,
      ''code'', ''REGISTRATION_PROMPT'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', jsonb_build_object(
        ''contentSource'', ''shared_light'',
        ''currentShareLightId'', v_share.id::text,
        ''currentShareToken'', v_token,
        ''currentExperienceId'', COALESCE(v_share.experience_id::text, ''''),
        ''currentResourceId'', COALESCE(v_share.resource_id::text, ''''),
        ''currentExperienceRunId'', COALESCE(v_run_id::text, ''''),
        ''experience_run_id'', COALESCE(v_run_id::text, ''''),
        ''showRegistrationPrompt'', true
      )
    );
  END IF;

  v_node := public.lumi_get_node(''HOME_DEFAULT'');

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''HOME_DEFAULT'',
    ''content_type'', ''empty_presence'',
    ''content'', jsonb_build_object(''type'', ''empty_presence''),
    ''state'', jsonb_build_object(
      ''contentSource'', ''shared_light'',
      ''currentShareLightId'', v_share.id::text,
      ''currentShareToken'', v_token,
      ''currentExperienceId'', COALESCE(v_share.experience_id::text, ''''),
      ''currentResourceId'', COALESCE(v_share.resource_id::text, ''''),
      ''currentExperienceRunId'', COALESCE(v_run_id::text, ''''),
      ''experience_run_id'', COALESCE(v_run_id::text, '''')
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('410', 'CREATE OR REPLACE FUNCTION public.lumi_track_share_light_event(p_params jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_user_id uuid;
  v_share_light_id uuid;
  v_event_text text;
  v_channel_text text;
  v_event_type public.share_light_event_type;
  v_channel public.share_light_channel;
  v_share record;
  v_node jsonb;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_user_id := NULLIF(TRIM(COALESCE(
    p_params->>''user_id'',
    p_params->>''currentUserId'',
    ''''
  )), '''')::uuid;

  v_share_light_id := NULLIF(TRIM(COALESCE(
    p_params->>''share_light_id'',
    p_params->>''currentShareLightId'',
    ''''
  )), '''')::uuid;

  v_event_text := COALESCE(NULLIF(TRIM(p_params->>''event_type''), ''''), ''prepared'');
  v_channel_text := COALESCE(NULLIF(TRIM(p_params->>''channel''), ''''), ''unknown'');

  v_event_type := CASE
    WHEN v_event_text IN (''prepared'', ''edited'', ''copied'', ''native_share_opened'', ''shared'', ''failed'', ''revoked'', ''opened'')
      THEN v_event_text::public.share_light_event_type
    ELSE ''prepared''::public.share_light_event_type
  END;

  v_channel := CASE
    WHEN v_channel_text IN (''clipboard'', ''native_share'', ''manual'', ''link'', ''whatsapp'', ''email'')
      THEN v_channel_text::public.share_light_channel
    ELSE ''unknown''::public.share_light_channel
  END;

  IF v_share_light_id IS NULL THEN
    v_node := public.lumi_get_node(''SHARE_LIGHT_EVENT_REQUIRES_ID'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARE_LIGHT_EVENT_REQUIRES_ID'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  SELECT *
  INTO v_share
  FROM public.share_light_circulations
  WHERE id = v_share_light_id
    AND (v_user_id IS NULL OR created_by_user_id = v_user_id)
  LIMIT 1;

  IF NOT FOUND THEN
    v_node := public.lumi_get_node(''SHARE_LIGHT_NOT_FOUND'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARE_LIGHT_NOT_FOUND'',
      ''content_type'', ''empty_presence'',
      ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
      ''state'', ''{}''::jsonb
    );
  END IF;

  INSERT INTO public.share_light_events (
    share_light_id,
    user_id,
    session_id,
    event_type,
    channel,
    surface,
    success,
    metadata
  )
  VALUES (
    v_share.id,
    COALESCE(v_user_id, v_share.created_by_user_id),
    v_share.session_id,
    v_event_type,
    v_channel,
    v_share.source_surface,
    COALESCE((p_params->>''success'')::boolean, true),
    COALESCE(p_params->''metadata'', ''{}''::jsonb)
  );

  v_node := public.lumi_get_node(''SHARE_LIGHT_EVENT_TRACKED'');

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''SHARE_LIGHT_EVENT_TRACKED'',
    ''content_type'', ''empty_presence'',
    ''content'', COALESCE(v_node->''content'', jsonb_build_object(''type'', ''empty_presence'')),
    ''state'', ''{}''::jsonb
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('411', 'CREATE OR REPLACE FUNCTION public.lumi_update_share_light_text(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_res jsonb;
  v_content jsonb;
  v_state jsonb;
  v_token text;
  v_share_path text;
  v_node jsonb;
BEGIN
  v_res := public.lumi_update_share_light_text__core(p_params);

  IF COALESCE((v_res->>''ok'')::boolean, false) IS NOT TRUE THEN
    RETURN v_res;
  END IF;

  v_content := COALESCE(v_res->''content'', ''{}''::jsonb);
  v_state   := COALESCE(v_res->''state'', ''{}''::jsonb);

  v_token := COALESCE(
    NULLIF(v_content->>''share_token'', ''''),
    NULLIF(v_state->>''currentShareToken'', ''''),
    NULLIF(p_params->>''share_token'', '''')
  );

  IF v_token IS NOT NULL THEN
    v_share_path := ''/?share_light='' || v_token;
    v_content := v_content || jsonb_build_object(''share_token'', v_token, ''share_path'', v_share_path, ''share_url'', '''');
    v_state := v_state || jsonb_build_object(''currentShareToken'', v_token);
  END IF;

  v_content := v_content || jsonb_build_object(
    ''type'', ''share_light_editor'',
    ''source'', ''share_light'',
    ''editor_title'', COALESCE(NULLIF(v_content->>''editor_title'', ''''), ''Compartir luz''),
    ''editor_subtitle'', ''Podés ajustar el texto antes de compartirlo.'',
    ''editor_helper'', ''LUMEN nunca incluye tu nota personal, tu estado ni tu Santuario privado.'',
    ''privacy_hint'', ''Tu Santuario sigue siendo privado''
  );

  v_node := public.lumi_get_node(''SHARE_LIGHT_EDITOR'');

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''SHARE_LIGHT_EDITOR'',
    ''content_type'', ''share_light_editor'',
    ''content'', v_content,
    ''state'', v_state
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('412', 'CREATE OR REPLACE FUNCTION public.lumi_update_share_light_text__core(p_params jsonb DEFAULT ''{}''::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO ''public''
AS $function$
DECLARE
  v_user_id uuid;
  v_share_light_id uuid;
  v_text text;
  v_share record;
  v_node jsonb;
BEGIN
  p_params := public.lumi_normalize_params(COALESCE(p_params, ''{}''::jsonb));

  v_user_id := NULLIF(TRIM(COALESCE(p_params->>''user_id'', p_params->>''currentUserId'', '''')), '''')::uuid;
  v_share_light_id := NULLIF(TRIM(COALESCE(p_params->>''share_light_id'', p_params->>''currentShareLightId'', '''')), '''')::uuid;
  v_text := NULLIF(TRIM(COALESCE(p_params->>''editable_text'', p_params->>''share_text'', '''')), '''');

  IF v_share_light_id IS NULL OR v_text IS NULL THEN
    v_node := public.lumi_get_node(''SHARE_LIGHT_FAILED'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARE_LIGHT_FAILED'',
      ''content_type'', ''share_light_editor'',
      ''content'', jsonb_build_object(''type'', ''share_light_editor'', ''status'', ''failed''),
      ''state'', ''{}''::jsonb
    );
  END IF;

  UPDATE public.share_light_circulations
  SET editable_text = v_text, status = ''edited'', updated_at = now()
  WHERE id = v_share_light_id
    AND (v_user_id IS NULL OR created_by_user_id = v_user_id)
    AND status NOT IN (''revoked'', ''expired'')
  RETURNING * INTO v_share;

  IF NOT FOUND THEN
    v_node := public.lumi_get_node(''SHARE_LIGHT_FAILED'');
    RETURN v_node || jsonb_build_object(
      ''ok'', false,
      ''code'', ''SHARE_LIGHT_FAILED'',
      ''content_type'', ''share_light_editor'',
      ''content'', jsonb_build_object(''type'', ''share_light_editor'', ''status'', ''failed''),
      ''state'', ''{}''::jsonb
    );
  END IF;

  INSERT INTO public.share_light_events (
    share_light_id, user_id, session_id, event_type, channel, surface, success, metadata
  )
  VALUES (
    v_share.id, COALESCE(v_user_id, v_share.created_by_user_id), v_share.session_id,
    ''edited'', ''manual'', v_share.source_surface, true,
    jsonb_build_object(''text_length'', length(v_text))
  );

  v_node := public.lumi_get_node(''SHARE_LIGHT_EDITOR'');

  RETURN v_node || jsonb_build_object(
    ''ok'', true,
    ''code'', ''SHARE_LIGHT_EDITOR'',
    ''content_type'', ''share_light_editor'',
    ''content'', jsonb_build_object(
      ''type'', ''share_light_editor'',
      ''share_light_id'', v_share.id,
      ''share_token'', v_share.share_token,
      ''editable_text'', v_share.editable_text,
      ''share_text'', v_share.editable_text,
      ''status'', v_share.status
    ),
    ''state'', jsonb_build_object(
      ''currentShareLightId'', v_share.id,
      ''currentShareToken'', v_share.share_token
    )
  );
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('413', 'CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('417', 'CREATE OR REPLACE FUNCTION realtime."cast"(val text, type_ regtype)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
declare
  res jsonb;
begin
  if type_::text = ''bytea'' then
    return to_jsonb(val);
  end if;
  execute format(''select to_jsonb(%L::''|| type_::text || '')'', val) into res;
  return res;
end
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('419', 'CREATE OR REPLACE FUNCTION realtime.check_equality_op(op realtime.equality_op, type_ regtype, val_1 text, val_2 text, negate boolean)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE
AS $function$
declare
    op_symbol text;
    res boolean;
begin
    -- IS DISTINCT FROM / IS NOT DISTINCT FROM: infix, both sides typed literals
    if op = ''isdistinct'' then
        execute format(
            ''select %L::%s %s %L::%s'',
            val_1,
            type_::text,
            case when negate then ''IS NOT DISTINCT FROM'' else ''IS DISTINCT FROM'' end,
            val_2,
            type_::text
        ) into res;
        return res;
    end if;

    -- IS requires a keyword RHS (NULL, TRUE, FALSE, UNKNOWN), not a typed literal
    if op = ''is'' then
        if val_2 not in (''null'', ''true'', ''false'', ''unknown'') then
            raise exception ''invalid value for is filter: must be null, true, false, or unknown'';
        end if;
        execute format(
            ''select %L::%s %s %s'',
            val_1,
            type_::text,
            case when negate then ''IS NOT'' else ''IS'' end,
            upper(val_2)
        ) into res;
        return res;
    end if;

    op_symbol = case
        when op = ''eq''    then ''=''
        when op = ''neq''   then ''!=''
        when op = ''lt''    then ''<''
        when op = ''lte''   then ''<=''
        when op = ''gt''    then ''>''
        when op = ''gte''   then ''>=''
        when op = ''in''    then ''= any''
        when op = ''like''   then ''LIKE''
        when op = ''ilike''  then ''ILIKE''
        when op = ''match''  then ''~''
        when op = ''imatch'' then ''~*''
        else null
    end;

    if op_symbol is null then
        raise exception ''unsupported equality operator: %'', op::text;
    end if;

    execute format(
        ''select %L::%s %s (%L::%s)'',
        val_1,
        type_::text,
        op_symbol,
        val_2,
        case when op = ''in'' then type_::text || ''[]'' else type_::text end
    ) into res;

    return case when negate then not res else res end;
end;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('423', 'CREATE OR REPLACE FUNCTION realtime.send(payload jsonb, event text, topic text, private boolean DEFAULT true)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  generated_id uuid;
  final_payload jsonb;
BEGIN
  BEGIN
    generated_id := gen_random_uuid();

    -- Check if payload has an ''id'' key, if not, add the generated UUID
    IF payload ? ''id'' THEN
      final_payload := payload;
    ELSE
      final_payload := jsonb_set(payload, ''{id}'', to_jsonb(generated_id));
    END IF;

    -- Set the topic configuration
    EXECUTE format(''SET LOCAL realtime.topic TO %L'', topic);

    INSERT INTO realtime.messages (id, payload, event, topic, private, extension)
    VALUES (generated_id, final_payload, event, topic, private, ''broadcast'');
  EXCEPTION
    WHEN OTHERS THEN
      RAISE WARNING ''WarnSendingBroadcastMessage: %'', SQLERRM;
  END;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('424', 'CREATE OR REPLACE FUNCTION realtime.send_binary(payload bytea, event text, topic text, private boolean DEFAULT true)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  generated_id uuid;
BEGIN
  BEGIN
    generated_id := gen_random_uuid();

    EXECUTE format(''SET LOCAL realtime.topic TO %L'', topic);

    INSERT INTO realtime.messages (id, binary_payload, event, topic, private, extension)
    VALUES (generated_id, payload, event, topic, private, ''broadcast'');
  EXCEPTION
    WHEN OTHERS THEN
      RAISE WARNING ''WarnSendingBroadcastMessage: %'', SQLERRM;
  END;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('425', 'CREATE OR REPLACE FUNCTION realtime.subscription_check_filters()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
declare
    col_names text[] = coalesce(
            array_agg(a.attname order by a.attnum),
            ''{}''::text[]
        )
        from
            pg_catalog.pg_attribute a
        where
            a.attrelid = new.entity
            and a.attnum > 0
            and not a.attisdropped
            and pg_catalog.has_column_privilege(
                (new.claims ->> ''role''),
                a.attrelid,
                a.attnum,
                ''SELECT''
            );
    filter realtime.user_defined_filter;
    col_type regtype;
    in_val jsonb;
    selected_col text;
begin
    for filter in select * from unnest(new.filters) loop
        if not filter.column_name = any(col_names) then
            raise exception ''invalid column for filter %'', filter.column_name;
        end if;

        col_type = (
            select atttypid::regtype
            from pg_catalog.pg_attribute
            where attrelid = new.entity
                  and attname = filter.column_name
        );
        if col_type is null then
            raise exception ''failed to lookup type for column %'', filter.column_name;
        end if;

        if filter.op = ''in''::realtime.equality_op then
            in_val = realtime.cast(filter.value, (col_type::text || ''[]'')::regtype);
            if coalesce(jsonb_array_length(in_val), 0) > 100 then
                raise exception ''too many values for `in` filter. Maximum 100'';
            end if;
        elsif filter.op = ''is''::realtime.equality_op then
            -- `is` requires a keyword RHS rather than a typed literal
            if filter.value not in (''null'', ''true'', ''false'', ''unknown'') then
                raise exception ''invalid value for is filter: must be null, true, false, or unknown'';
            end if;
            -- IS NULL works for any type, but IS TRUE/FALSE/UNKNOWN require a boolean
            -- operand. Reject the non-null keywords on non-boolean columns here so they
            -- don''t abort apply_rls at WAL time.
            if filter.value <> ''null'' and col_type <> ''boolean''::regtype then
                raise exception ''is % filter requires a boolean column, got %'', filter.value, col_type::text;
            end if;
        elsif filter.op in (''like''::realtime.equality_op, ''ilike''::realtime.equality_op) then
            -- like/ilike apply the text pattern operator (~~); reject column types that
            -- have no such operator instead of failing at WAL time
            if not exists (
                select 1 from pg_catalog.pg_operator
                where oprname = ''~~'' and oprleft = col_type
            ) then
                raise exception ''operator % requires a text-compatible column type, got %'', filter.op::text, col_type::text;
            end if;
        elsif filter.op in (''match''::realtime.equality_op, ''imatch''::realtime.equality_op) then
            -- match/imatch apply the regex operators ~ / ~*; reject column types that have
            -- no such operator (e.g. integer) instead of failing at WAL time, mirroring the
            -- like/ilike guard above.
            if not exists (
                select 1 from pg_catalog.pg_operator
                where oprname = case when filter.op = ''imatch''::realtime.equality_op then ''~*'' else ''~'' end
                  and oprleft = col_type
                  and oprright = col_type
                  and oprresult = ''boolean''::regtype
            ) then
                raise exception ''operator % requires a text-compatible column type, got %'', filter.op::text, col_type::text;
            end if;
            -- validate the regex eagerly so a bad pattern is rejected here, not inside
            -- apply_rls where it would abort the WAL stream for the entity
            begin
                perform '''' ~ filter.value;
            exception when others then
                raise exception ''invalid regular expression for % filter: %'', filter.op::text, sqlerrm;
            end;
        else
            -- eq/neq/lt/lte/gt/gte: value must be coercable to the type
            perform realtime.cast(filter.value, col_type);
        end if;
    end loop;

    if new.selected_columns is not null then
        for selected_col in select * from unnest(new.selected_columns) loop
            if not selected_col = any(col_names) then
                raise exception ''invalid column for select %'', selected_col;
            end if;
        end loop;
    end if;

    -- Apply consistent order to filters so the unique constraint can''t be tricked by a
    -- different filter order. negate is part of the sort key.
    new.filters = coalesce(
        array_agg(f order by f.column_name, f.op, f.value, f.negate),
        ''{}''
    ) from unnest(new.filters) f;

    new.selected_columns = (
        select array_agg(c order by c)
        from unnest(new.selected_columns) c
    );

    return new;
end;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('432', 'CREATE OR REPLACE FUNCTION storage.enforce_bucket_name_length()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
    if length(new.name) > 100 then
        raise exception ''bucket name "%" is too long (% characters). Max is 100.'', new.name, length(new.name);
    end if;
    return new;
end;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('433', 'CREATE OR REPLACE FUNCTION storage.extension(name text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
    _parts text[];
    _filename text;
BEGIN
    -- Split on "/" to get path segments
    SELECT string_to_array(name, ''/'') INTO _parts;
    -- Get the last path segment (the actual filename)
    SELECT _parts[array_length(_parts, 1)] INTO _filename;
    -- Extract extension: reverse, split on ''.'', then reverse again
    RETURN reverse(split_part(reverse(_filename), ''.'', 1));
END
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('434', 'CREATE OR REPLACE FUNCTION storage.filename(name text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
_parts text[];
BEGIN
	select string_to_array(name, ''/'') into _parts;
	return _parts[array_length(_parts,1)];
END
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('439', 'CREATE OR REPLACE FUNCTION storage.list_objects_with_delimiter(_bucket_id text, prefix_param text, delimiter_param text, max_keys integer DEFAULT 100, start_after text DEFAULT ''''::text, next_token text DEFAULT ''''::text, sort_order text DEFAULT ''asc''::text)
 RETURNS TABLE(name text, id uuid, metadata jsonb, updated_at timestamp with time zone, created_at timestamp with time zone, last_accessed_at timestamp with time zone)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_peek_name TEXT;
    v_current RECORD;
    v_common_prefix TEXT;

    -- Configuration
    v_is_asc BOOLEAN;
    v_prefix TEXT;
    v_start TEXT;
    v_upper_bound TEXT;
    v_file_batch_size INT;

    -- Seek state
    v_next_seek TEXT;
    v_count INT := 0;

    -- Dynamic SQL for batch query only
    v_batch_query TEXT;

BEGIN
    -- ========================================================================
    -- INITIALIZATION
    -- ========================================================================
    v_is_asc := lower(coalesce(sort_order, ''asc'')) = ''asc'';
    v_prefix := coalesce(prefix_param, '''');
    v_start := CASE WHEN coalesce(next_token, '''') <> '''' THEN next_token ELSE coalesce(start_after, '''') END;
    v_file_batch_size := LEAST(GREATEST(max_keys * 2, 100), 1000);

    -- Calculate upper bound for prefix filtering (bytewise, using COLLATE "C")
    IF v_prefix = '''' THEN
        v_upper_bound := NULL;
    ELSIF right(v_prefix, 1) = delimiter_param THEN
        v_upper_bound := left(v_prefix, -1) || chr(ascii(delimiter_param) + 1);
    ELSE
        v_upper_bound := left(v_prefix, -1) || chr(ascii(right(v_prefix, 1)) + 1);
    END IF;

    -- Build batch query (dynamic SQL - called infrequently, amortized over many rows)
    IF v_is_asc THEN
        IF v_upper_bound IS NOT NULL THEN
            v_batch_query := ''SELECT o.name, o.id, o.updated_at, o.created_at, o.last_accessed_at, o.metadata '' ||
                ''FROM storage.objects o WHERE o.bucket_id = $1 AND o.name COLLATE "C" >= $2 '' ||
                ''AND o.name COLLATE "C" < $3 ORDER BY o.name COLLATE "C" ASC LIMIT $4'';
        ELSE
            v_batch_query := ''SELECT o.name, o.id, o.updated_at, o.created_at, o.last_accessed_at, o.metadata '' ||
                ''FROM storage.objects o WHERE o.bucket_id = $1 AND o.name COLLATE "C" >= $2 '' ||
                ''ORDER BY o.name COLLATE "C" ASC LIMIT $4'';
        END IF;
    ELSE
        IF v_upper_bound IS NOT NULL THEN
            v_batch_query := ''SELECT o.name, o.id, o.updated_at, o.created_at, o.last_accessed_at, o.metadata '' ||
                ''FROM storage.objects o WHERE o.bucket_id = $1 AND o.name COLLATE "C" < $2 '' ||
                ''AND o.name COLLATE "C" >= $3 ORDER BY o.name COLLATE "C" DESC LIMIT $4'';
        ELSE
            v_batch_query := ''SELECT o.name, o.id, o.updated_at, o.created_at, o.last_accessed_at, o.metadata '' ||
                ''FROM storage.objects o WHERE o.bucket_id = $1 AND o.name COLLATE "C" < $2 '' ||
                ''ORDER BY o.name COLLATE "C" DESC LIMIT $4'';
        END IF;
    END IF;

    -- ========================================================================
    -- SEEK INITIALIZATION: Determine starting position
    -- ========================================================================
    IF v_start = '''' THEN
        IF v_is_asc THEN
            v_next_seek := v_prefix;
        ELSE
            -- DESC without cursor: find the last item in range
            IF v_upper_bound IS NOT NULL THEN
                SELECT o.name INTO v_next_seek FROM storage.objects o
                WHERE o.bucket_id = _bucket_id AND o.name COLLATE "C" >= v_prefix AND o.name COLLATE "C" < v_upper_bound
                ORDER BY o.name COLLATE "C" DESC LIMIT 1;
            ELSIF v_prefix <> '''' THEN
                SELECT o.name INTO v_next_seek FROM storage.objects o
                WHERE o.bucket_id = _bucket_id AND o.name COLLATE "C" >= v_prefix
                ORDER BY o.name COLLATE "C" DESC LIMIT 1;
            ELSE
                SELECT o.name INTO v_next_seek FROM storage.objects o
                WHERE o.bucket_id = _bucket_id
                ORDER BY o.name COLLATE "C" DESC LIMIT 1;
            END IF;

            IF v_next_seek IS NOT NULL THEN
                v_next_seek := v_next_seek || delimiter_param;
            ELSE
                RETURN;
            END IF;
        END IF;
    ELSE
        -- Cursor provided: determine if it refers to a folder or leaf
        IF EXISTS (
            SELECT 1 FROM storage.objects o
            WHERE o.bucket_id = _bucket_id
              AND o.name COLLATE "C" LIKE v_start || delimiter_param || ''%''
            LIMIT 1
        ) THEN
            -- Cursor refers to a folder
            IF v_is_asc THEN
                v_next_seek := v_start || chr(ascii(delimiter_param) + 1);
            ELSE
                v_next_seek := v_start || delimiter_param;
            END IF;
        ELSE
            -- Cursor refers to a leaf object
            IF v_is_asc THEN
                v_next_seek := v_start || delimiter_param;
            ELSE
                v_next_seek := v_start;
            END IF;
        END IF;
    END IF;

    -- ========================================================================
    -- MAIN LOOP: Hybrid peek-then-batch algorithm
    -- Uses STATIC SQL for peek (hot path) and DYNAMIC SQL for batch
    -- ========================================================================
    LOOP
        EXIT WHEN v_count >= max_keys;

        -- STEP 1: PEEK using STATIC SQL (plan cached, very fast)
        IF v_is_asc THEN
            IF v_upper_bound IS NOT NULL THEN
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = _bucket_id AND o.name COLLATE "C" >= v_next_seek AND o.name COLLATE "C" < v_upper_bound
                ORDER BY o.name COLLATE "C" ASC LIMIT 1;
            ELSE
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = _bucket_id AND o.name COLLATE "C" >= v_next_seek
                ORDER BY o.name COLLATE "C" ASC LIMIT 1;
            END IF;
        ELSE
            IF v_upper_bound IS NOT NULL THEN
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = _bucket_id AND o.name COLLATE "C" < v_next_seek AND o.name COLLATE "C" >= v_prefix
                ORDER BY o.name COLLATE "C" DESC LIMIT 1;
            ELSIF v_prefix <> '''' THEN
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = _bucket_id AND o.name COLLATE "C" < v_next_seek AND o.name COLLATE "C" >= v_prefix
                ORDER BY o.name COLLATE "C" DESC LIMIT 1;
            ELSE
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = _bucket_id AND o.name COLLATE "C" < v_next_seek
                ORDER BY o.name COLLATE "C" DESC LIMIT 1;
            END IF;
        END IF;

        EXIT WHEN v_peek_name IS NULL;

        -- STEP 2: Check if this is a FOLDER or FILE
        v_common_prefix := storage.get_common_prefix(v_peek_name, v_prefix, delimiter_param);

        IF v_common_prefix IS NOT NULL THEN
            -- FOLDER: Emit and skip to next folder (no heap access needed)
            name := rtrim(v_common_prefix, delimiter_param);
            id := NULL;
            updated_at := NULL;
            created_at := NULL;
            last_accessed_at := NULL;
            metadata := NULL;
            RETURN NEXT;
            v_count := v_count + 1;

            -- Advance seek past the folder range
            IF v_is_asc THEN
                v_next_seek := left(v_common_prefix, -1) || chr(ascii(delimiter_param) + 1);
            ELSE
                v_next_seek := v_common_prefix;
            END IF;
        ELSE
            -- FILE: Batch fetch using DYNAMIC SQL (overhead amortized over many rows)
            -- For ASC: upper_bound is the exclusive upper limit (< condition)
            -- For DESC: prefix is the inclusive lower limit (>= condition)
            FOR v_current IN EXECUTE v_batch_query USING _bucket_id, v_next_seek,
                CASE WHEN v_is_asc THEN COALESCE(v_upper_bound, v_prefix) ELSE v_prefix END, v_file_batch_size
            LOOP
                v_common_prefix := storage.get_common_prefix(v_current.name, v_prefix, delimiter_param);

                IF v_common_prefix IS NOT NULL THEN
                    -- Hit a folder: exit batch, let peek handle it
                    v_next_seek := v_current.name;
                    EXIT;
                END IF;

                -- Emit file
                name := v_current.name;
                id := v_current.id;
                updated_at := v_current.updated_at;
                created_at := v_current.created_at;
                last_accessed_at := v_current.last_accessed_at;
                metadata := v_current.metadata;
                RETURN NEXT;
                v_count := v_count + 1;

                -- Advance seek past this file
                IF v_is_asc THEN
                    v_next_seek := v_current.name || delimiter_param;
                ELSE
                    v_next_seek := v_current.name;
                END IF;

                EXIT WHEN v_count >= max_keys;
            END LOOP;
        END IF;
    END LOOP;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('440', 'CREATE OR REPLACE FUNCTION storage.operation()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
    RETURN current_setting(''storage.operation'', true);
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('441', 'CREATE OR REPLACE FUNCTION storage.protect_delete()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Check if storage.allow_delete_query is set to ''true''
    IF COALESCE(current_setting(''storage.allow_delete_query'', true), ''false'') != ''true'' THEN
        RAISE EXCEPTION ''Direct deletion from storage tables is not allowed. Use the Storage API instead.''
            USING HINT = ''This prevents accidental data loss from orphaned objects.'',
                  ERRCODE = ''42501'';
    END IF;
    RETURN NULL;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('442', 'CREATE OR REPLACE FUNCTION storage.search(prefix text, bucketname text, limits integer DEFAULT 100, levels integer DEFAULT 1, offsets integer DEFAULT 0, search text DEFAULT ''''::text, sortcolumn text DEFAULT ''name''::text, sortorder text DEFAULT ''asc''::text)
 RETURNS TABLE(name text, id uuid, updated_at timestamp with time zone, created_at timestamp with time zone, last_accessed_at timestamp with time zone, metadata jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_peek_name TEXT;
    v_current RECORD;
    v_common_prefix TEXT;
    v_delimiter CONSTANT TEXT := ''/'';

    -- Configuration
    v_limit INT;
    v_prefix TEXT;
    v_prefix_lower TEXT;
    v_is_asc BOOLEAN;
    v_order_by TEXT;
    v_sort_order TEXT;
    v_upper_bound TEXT;
    v_file_batch_size INT;

    -- Dynamic SQL for batch query only
    v_batch_query TEXT;

    -- Seek state
    v_next_seek TEXT;
    v_count INT := 0;
    v_skipped INT := 0;
BEGIN
    -- ========================================================================
    -- INITIALIZATION
    -- ========================================================================
    v_limit := LEAST(coalesce(limits, 100), 1500);
    v_prefix := coalesce(prefix, '''') || coalesce(search, '''');
    v_prefix_lower := lower(v_prefix);
    v_is_asc := lower(coalesce(sortorder, ''asc'')) = ''asc'';
    v_file_batch_size := LEAST(GREATEST(v_limit * 2, 100), 1000);

    -- Validate sort column
    CASE lower(coalesce(sortcolumn, ''name''))
        WHEN ''name'' THEN v_order_by := ''name'';
        WHEN ''updated_at'' THEN v_order_by := ''updated_at'';
        WHEN ''created_at'' THEN v_order_by := ''created_at'';
        WHEN ''last_accessed_at'' THEN v_order_by := ''last_accessed_at'';
        ELSE v_order_by := ''name'';
    END CASE;

    v_sort_order := CASE WHEN v_is_asc THEN ''asc'' ELSE ''desc'' END;

    -- ========================================================================
    -- NON-NAME SORTING: Use path_tokens approach (unchanged)
    -- ========================================================================
    IF v_order_by != ''name'' THEN
        RETURN QUERY EXECUTE format(
            $sql$
            WITH folders AS (
                SELECT path_tokens[$1] AS folder
                FROM storage.objects
                WHERE objects.name ILIKE $2 || ''%%''
                  AND bucket_id = $3
                  AND array_length(objects.path_tokens, 1) <> $1
                GROUP BY folder
                ORDER BY folder %s
            )
            (SELECT folder AS "name",
                   NULL::uuid AS id,
                   NULL::timestamptz AS updated_at,
                   NULL::timestamptz AS created_at,
                   NULL::timestamptz AS last_accessed_at,
                   NULL::jsonb AS metadata FROM folders)
            UNION ALL
            (SELECT path_tokens[$1] AS "name",
                   id, updated_at, created_at, last_accessed_at, metadata
             FROM storage.objects
             WHERE objects.name ILIKE $2 || ''%%''
               AND bucket_id = $3
               AND array_length(objects.path_tokens, 1) = $1
             ORDER BY %I %s)
            LIMIT $4 OFFSET $5
            $sql$, v_sort_order, v_order_by, v_sort_order
        ) USING levels, v_prefix, bucketname, v_limit, offsets;
        RETURN;
    END IF;

    -- ========================================================================
    -- NAME SORTING: Hybrid skip-scan with batch optimization
    -- ========================================================================

    -- Calculate upper bound for prefix filtering
    IF v_prefix_lower = '''' THEN
        v_upper_bound := NULL;
    ELSIF right(v_prefix_lower, 1) = v_delimiter THEN
        v_upper_bound := left(v_prefix_lower, -1) || chr(ascii(v_delimiter) + 1);
    ELSE
        v_upper_bound := left(v_prefix_lower, -1) || chr(ascii(right(v_prefix_lower, 1)) + 1);
    END IF;

    -- Build batch query (dynamic SQL - called infrequently, amortized over many rows)
    IF v_is_asc THEN
        IF v_upper_bound IS NOT NULL THEN
            v_batch_query := ''SELECT o.name, o.id, o.updated_at, o.created_at, o.last_accessed_at, o.metadata '' ||
                ''FROM storage.objects o WHERE o.bucket_id = $1 AND lower(o.name) COLLATE "C" >= $2 '' ||
                ''AND lower(o.name) COLLATE "C" < $3 ORDER BY lower(o.name) COLLATE "C" ASC LIMIT $4'';
        ELSE
            v_batch_query := ''SELECT o.name, o.id, o.updated_at, o.created_at, o.last_accessed_at, o.metadata '' ||
                ''FROM storage.objects o WHERE o.bucket_id = $1 AND lower(o.name) COLLATE "C" >= $2 '' ||
                ''ORDER BY lower(o.name) COLLATE "C" ASC LIMIT $4'';
        END IF;
    ELSE
        IF v_upper_bound IS NOT NULL THEN
            v_batch_query := ''SELECT o.name, o.id, o.updated_at, o.created_at, o.last_accessed_at, o.metadata '' ||
                ''FROM storage.objects o WHERE o.bucket_id = $1 AND lower(o.name) COLLATE "C" < $2 '' ||
                ''AND lower(o.name) COLLATE "C" >= $3 ORDER BY lower(o.name) COLLATE "C" DESC LIMIT $4'';
        ELSE
            v_batch_query := ''SELECT o.name, o.id, o.updated_at, o.created_at, o.last_accessed_at, o.metadata '' ||
                ''FROM storage.objects o WHERE o.bucket_id = $1 AND lower(o.name) COLLATE "C" < $2 '' ||
                ''ORDER BY lower(o.name) COLLATE "C" DESC LIMIT $4'';
        END IF;
    END IF;

    -- Initialize seek position
    IF v_is_asc THEN
        v_next_seek := v_prefix_lower;
    ELSE
        -- DESC: find the last item in range first (static SQL)
        IF v_upper_bound IS NOT NULL THEN
            SELECT o.name INTO v_peek_name FROM storage.objects o
            WHERE o.bucket_id = bucketname AND lower(o.name) COLLATE "C" >= v_prefix_lower AND lower(o.name) COLLATE "C" < v_upper_bound
            ORDER BY lower(o.name) COLLATE "C" DESC LIMIT 1;
        ELSIF v_prefix_lower <> '''' THEN
            SELECT o.name INTO v_peek_name FROM storage.objects o
            WHERE o.bucket_id = bucketname AND lower(o.name) COLLATE "C" >= v_prefix_lower
            ORDER BY lower(o.name) COLLATE "C" DESC LIMIT 1;
        ELSE
            SELECT o.name INTO v_peek_name FROM storage.objects o
            WHERE o.bucket_id = bucketname
            ORDER BY lower(o.name) COLLATE "C" DESC LIMIT 1;
        END IF;

        IF v_peek_name IS NOT NULL THEN
            v_next_seek := lower(v_peek_name) || v_delimiter;
        ELSE
            RETURN;
        END IF;
    END IF;

    -- ========================================================================
    -- MAIN LOOP: Hybrid peek-then-batch algorithm
    -- Uses STATIC SQL for peek (hot path) and DYNAMIC SQL for batch
    -- ========================================================================
    LOOP
        EXIT WHEN v_count >= v_limit;

        -- STEP 1: PEEK using STATIC SQL (plan cached, very fast)
        IF v_is_asc THEN
            IF v_upper_bound IS NOT NULL THEN
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = bucketname AND lower(o.name) COLLATE "C" >= v_next_seek AND lower(o.name) COLLATE "C" < v_upper_bound
                ORDER BY lower(o.name) COLLATE "C" ASC LIMIT 1;
            ELSE
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = bucketname AND lower(o.name) COLLATE "C" >= v_next_seek
                ORDER BY lower(o.name) COLLATE "C" ASC LIMIT 1;
            END IF;
        ELSE
            IF v_upper_bound IS NOT NULL THEN
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = bucketname AND lower(o.name) COLLATE "C" < v_next_seek AND lower(o.name) COLLATE "C" >= v_prefix_lower
                ORDER BY lower(o.name) COLLATE "C" DESC LIMIT 1;
            ELSIF v_prefix_lower <> '''' THEN
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = bucketname AND lower(o.name) COLLATE "C" < v_next_seek AND lower(o.name) COLLATE "C" >= v_prefix_lower
                ORDER BY lower(o.name) COLLATE "C" DESC LIMIT 1;
            ELSE
                SELECT o.name INTO v_peek_name FROM storage.objects o
                WHERE o.bucket_id = bucketname AND lower(o.name) COLLATE "C" < v_next_seek
                ORDER BY lower(o.name) COLLATE "C" DESC LIMIT 1;
            END IF;
        END IF;

        EXIT WHEN v_peek_name IS NULL;

        -- STEP 2: Check if this is a FOLDER or FILE
        v_common_prefix := storage.get_common_prefix(lower(v_peek_name), v_prefix_lower, v_delimiter);

        IF v_common_prefix IS NOT NULL THEN
            -- FOLDER: Handle offset, emit if needed, skip to next folder
            IF v_skipped < offsets THEN
                v_skipped := v_skipped + 1;
            ELSE
                name := split_part(rtrim(storage.get_common_prefix(v_peek_name, v_prefix, v_delimiter), v_delimiter), v_delimiter, levels);
                id := NULL;
                updated_at := NULL;
                created_at := NULL;
                last_accessed_at := NULL;
                metadata := NULL;
                RETURN NEXT;
                v_count := v_count + 1;
            END IF;

            -- Advance seek past the folder range
            IF v_is_asc THEN
                v_next_seek := lower(left(v_common_prefix, -1)) || chr(ascii(v_delimiter) + 1);
            ELSE
                v_next_seek := lower(v_common_prefix);
            END IF;
        ELSE
            -- FILE: Batch fetch using DYNAMIC SQL (overhead amortized over many rows)
            -- For ASC: upper_bound is the exclusive upper limit (< condition)
            -- For DESC: prefix_lower is the inclusive lower limit (>= condition)
            FOR v_current IN EXECUTE v_batch_query
                USING bucketname, v_next_seek,
                    CASE WHEN v_is_asc THEN COALESCE(v_upper_bound, v_prefix_lower) ELSE v_prefix_lower END, v_file_batch_size
            LOOP
                v_common_prefix := storage.get_common_prefix(lower(v_current.name), v_prefix_lower, v_delimiter);

                IF v_common_prefix IS NOT NULL THEN
                    -- Hit a folder: exit batch, let peek handle it
                    v_next_seek := lower(v_current.name);
                    EXIT;
                END IF;

                -- Handle offset skipping
                IF v_skipped < offsets THEN
                    v_skipped := v_skipped + 1;
                ELSE
                    -- Emit file
                    name := split_part(v_current.name, v_delimiter, levels);
                    id := v_current.id;
                    updated_at := v_current.updated_at;
                    created_at := v_current.created_at;
                    last_accessed_at := v_current.last_accessed_at;
                    metadata := v_current.metadata;
                    RETURN NEXT;
                    v_count := v_count + 1;
                END IF;

                -- Advance seek past this file
                IF v_is_asc THEN
                    v_next_seek := lower(v_current.name) || v_delimiter;
                ELSE
                    v_next_seek := lower(v_current.name);
                END IF;

                EXIT WHEN v_count >= v_limit;
            END LOOP;
        END IF;
    END LOOP;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('444', 'CREATE OR REPLACE FUNCTION storage.search_v2(prefix text, bucket_name text, limits integer DEFAULT 100, levels integer DEFAULT 1, start_after text DEFAULT ''''::text, sort_order text DEFAULT ''asc''::text, sort_column text DEFAULT ''name''::text, sort_column_after text DEFAULT ''''::text)
 RETURNS TABLE(key text, name text, id uuid, updated_at timestamp with time zone, created_at timestamp with time zone, last_accessed_at timestamp with time zone, metadata jsonb)
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
    v_sort_col text;
    v_sort_ord text;
    v_limit int;
BEGIN
    -- Cap limit to maximum of 1500 records
    v_limit := LEAST(coalesce(limits, 100), 1500);

    -- Validate and normalize sort_order
    v_sort_ord := lower(coalesce(sort_order, ''asc''));
    IF v_sort_ord NOT IN (''asc'', ''desc'') THEN
        v_sort_ord := ''asc'';
    END IF;

    -- Validate and normalize sort_column
    v_sort_col := lower(coalesce(sort_column, ''name''));
    IF v_sort_col NOT IN (''name'', ''updated_at'', ''created_at'') THEN
        v_sort_col := ''name'';
    END IF;

    -- Route to appropriate implementation
    IF v_sort_col = ''name'' THEN
        -- Use list_objects_with_delimiter for name sorting (most efficient: O(k * log n))
        RETURN QUERY
        SELECT
            split_part(l.name, ''/'', levels) AS key,
            l.name AS name,
            l.id,
            l.updated_at,
            l.created_at,
            l.last_accessed_at,
            l.metadata
        FROM storage.list_objects_with_delimiter(
            bucket_name,
            coalesce(prefix, ''''),
            ''/'',
            v_limit,
            start_after,
            '''',
            v_sort_ord
        ) l;
    ELSE
        -- Use aggregation approach for timestamp sorting
        -- Not efficient for large datasets but supports correct pagination
        RETURN QUERY SELECT * FROM storage.search_by_timestamp(
            prefix, bucket_name, v_limit, levels, start_after,
            v_sort_ord, v_sort_col, sort_column_after
        );
    END IF;
END;
$function$
');

INSERT INTO pg_temp_8.__export_sql (ord, line) VALUES ('445', 'CREATE OR REPLACE FUNCTION storage.update_updated_at_column()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    NEW.updated_at = now();
    RETURN NEW; 
END;
$function$
');

